     1→import { ChariowError } from "./errors.js"
     2→import { ApiResponse } from "./types/product.js"
     3→
     4→export interface ChariowConfig {
     5→  apiKey: string
     6→  baseUrl?: string
     7→}
     8→
     9→export class ChariowClient {
    10→  apiKey: string
    11→  baseUrl: string
    12→
    13→  constructor(config: ChariowConfig) {
    14→    this.apiKey = config.apiKey
    15→    this.baseUrl = config.baseUrl || "https://api.chariow.com/v1"
    16→  }
    17→
    18→  async request<T>(
    19→    path: string,
    20→    options: RequestInit = {}
    21→  ): Promise<T> {
    22→    const response = await fetch(
    23→      `${this.baseUrl}${path}`,
    24→      {
    25→        ...options,
    26→        headers: {
    27→          Authorization: `Bearer ${this.apiKey}`,
    28→          "Content-Type": "application/json",
    29→          ...(options.headers || {})
    30→        }
    31→      }
    32→    )
    33→
    34→    let data: unknown
    35→
    36→    try {
    37→      data = await response.json()
    38→    } catch {
    39→      data = null
    40→    }
    41→
    42→    if (!response.ok) {
    43→      throw new ChariowError(
    44→        (data as any)?.message || "Chariow API Error",
    45→        response.status,
    46→        data
    47→      )
    48→    }
    49→
    50→    // Si la réponse a une structure { message, data, errors }, extraire data
    51→    if (data && typeof data === 'object' && 'data' in data) {
    52→      return (data as ApiResponse<T>).data as T
    53→    }
    54→
    55→    return data as T
    56→  }
    57→}
    58→

