import fs from 'fs';
import os from 'os';
import path from 'path';
import crypto from 'crypto';

const CONFIG_DIR = path.join(os.homedir(), '.chariow');
const CONFIG_FILE = path.join(CONFIG_DIR, 'config.json');

export interface CliConfig {
  apiKey?: string;
  defaultPerPage?: number;
  theme?: 'dark' | 'light';
  notifications?: boolean;
  autoRefresh?: number;
  lastCheck?: string;
}

export function validateApiKey(key: string): boolean {
  return typeof key === 'string' && key.trim().length >= 8;
}

export function getConfig(): CliConfig | null {
  try {
    if (fs.existsSync(CONFIG_FILE)) {
      const content = fs.readFileSync(CONFIG_FILE, 'utf-8');
      const config = JSON.parse(content);
      if (!config.defaultPerPage) config.defaultPerPage = 20;
      if (!config.theme) config.theme = 'dark';
      return config;
    }
  } catch {
    console.error('Failed to read config');
  }
  return null;
}

export function setConfig(config: Partial<CliConfig>) {
  try {
    if (!fs.existsSync(CONFIG_DIR)) {
      fs.mkdirSync(CONFIG_DIR, { recursive: true });
    }
    const existing = getConfig() || {};
    const merged = { ...existing, ...config };
    if (merged.apiKey !== undefined && merged.apiKey !== null && !validateApiKey(merged.apiKey)) {
      throw new Error('Invalid API key format (minimum 8 characters)');
    }
    fs.writeFileSync(CONFIG_FILE, JSON.stringify(merged, null, 2));
    return true;
  } catch (error) {
    console.error('Failed to write config:', error);
    return false;
  }
}

export function encryptApiKey(key: string): string {
  const algorithm = 'aes-256-cbc';
  const keyBuffer = crypto.scryptSync('chariow-secret-key', 'salt', 32);
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv(algorithm, keyBuffer, iv);
  const encrypted = cipher.update(key, 'utf8', 'hex') + cipher.final('hex');
  return iv.toString('hex') + ':' + encrypted;
}

export function decryptApiKey(encryptedData: string): string {
  const [ivHex, encrypted] = encryptedData.split(':');
  const iv = Buffer.from(ivHex, 'hex');
  const keyBuffer = crypto.scryptSync('chariow-secret-key', 'salt', 32);
  const decipher = crypto.createDecipheriv('aes-256-cbc', keyBuffer, iv);
  return decipher.update(encrypted, 'hex', 'utf8') + decipher.final('utf8');
}

import { Chariow } from '../../index.js';
import { getConfig } from '../utils/config.js';
import chalk from 'chalk';
import Table from 'cli-table3';
import ora from 'ora';

export async function salesCommand(options: any) {
  const config = getConfig();

  if (!config?.apiKey) {
    console.log(chalk.red('\n❌ No API key found. Run: chariow config --set <token>\n'));
    process.exit(1);
  }

  const client = new Chariow(config.apiKey);

  if (options.list || (!options.get && !options.stats)) {
    const spinner = ora('Fetching sales...').start();
    try {
      const perPage = options.limit ? parseInt(options.limit) : 20;
      const response = await client.sales.list(undefined, perPage);
      spinner.succeed(`Found ${response.data.length} sales\n`);

      if (response.data.length === 0) {
        console.log(chalk.dim('No sales found.\n'));
        return;
      }

      const table = new Table({
        head: [
          chalk.cyan('ID'),
          chalk.cyan('Product ID'),
          chalk.cyan('Amount'),
          chalk.cyan('Currency'),
          chalk.cyan('Status'),
          chalk.cyan('Date')
        ],
        colWidths: [26, 26, 12, 10, 12, 22]
      });

      response.data.forEach(s => {
        const date = new Date(s.created_at).toLocaleString();
        table.push([
          s.id.slice(0, 22),
          s.product_id.slice(0, 22),
          chalk.green(s.amount.toLocaleString()),
          s.currency,
          s.status === 'completed'
            ? chalk.green('✓ completed')
            : chalk.yellow(s.status),
          date
        ]);
      });

      console.log(table.toString());

      if (response.pagination.has_more) {
        console.log(chalk.dim(`\n  ℹ  More sales available. Use --limit <n> to load more.\n`));
      }
    } catch (error: any) {
      spinner.fail('Failed to fetch sales');
      console.log(chalk.red(error.message));
    }
  } else if (options.get) {
    const spinner = ora(`Fetching sale ${options.get}...`).start();
    try {
      const sale = await client.sales.get(options.get);
      spinner.succeed();

      console.log('\n' + chalk.bold.cyan('🛒 Sale Details:\n'));

      const table = new Table({ colWidths: [20, 50] });
      table.push(
        [chalk.gray('ID:'), sale.id],
        [chalk.gray('Product ID:'), sale.product_id],
        [chalk.gray('Customer ID:'), sale.customer_id || chalk.dim('N/A')],
        [chalk.gray('Amount:'), chalk.green(`${sale.amount.toLocaleString()} ${sale.currency}`)],
        [chalk.gray('Status:'), sale.status === 'completed' ? chalk.green('✓ completed') : chalk.yellow(sale.status)],
        [chalk.gray('Date:'), new Date(sale.created_at).toLocaleString()]
      );

      console.log(table.toString());
      console.log('');
    } catch (error: any) {
      spinner.fail('Sale not found');
      console.log(chalk.red(error.message));
    }
  } else if (options.stats) {
    const spinner = ora('Computing sales statistics...').start();
    try {
      const response = await client.sales.list(undefined, 100);
      const sales = response.data;

      const total = sales.reduce((sum, s) => sum + s.amount, 0);
      const completed = sales.filter(s => s.status === 'completed');
      const currencies = [...new Set(sales.map(s => s.currency))];
      const avgAmount = sales.length > 0 ? total / sales.length : 0;

      spinner.succeed('Sales statistics\n');

      console.log(chalk.hex('#6366f1').bold('\n📊 SALES STATISTICS\n'));
      console.log(`  ${chalk.cyan('Total Sales:')}       ${chalk.white(sales.length)}`);
      console.log(`  ${chalk.cyan('Completed:')}         ${chalk.green(completed.length)}`);
      console.log(`  ${chalk.cyan('Pending/Other:')}     ${chalk.yellow(sales.length - completed.length)}`);
      console.log(`  ${chalk.cyan('Total Revenue:')}     ${chalk.green(total.toLocaleString())} ${currencies.join('/')}`);
      console.log(`  ${chalk.cyan('Avg Sale Value:')}    ${chalk.green(avgAmount.toFixed(2))} ${currencies[0] || ''}`);
      console.log('');
    } catch (error: any) {
      spinner.fail('Failed to load statistics');
      console.log(chalk.red(error.message));
    }
  }
}

import { Chariow } from '../../index.js';
import { getConfig } from '../utils/config.js';
import chalk from 'chalk';
import Table from 'cli-table3';
import ora from 'ora';

export async function storeCommand(options: any) {
  const config = getConfig();

  if (!config?.apiKey) {
    console.log(chalk.red('\n❌ No API key found. Run: chariow config --set <token>\n'));
    process.exit(1);
  }

  const client = new Chariow(config.apiKey);
  const spinner = ora('Fetching store information...').start();

  try {
    const store = await client.store.getInfo();
    spinner.succeed('Store information loaded\n');

    console.log(chalk.hex('#6366f1').bold('\n🏪 STORE INFORMATION\n'));

    const table = new Table({ colWidths: [22, 58] });

    table.push(
      [chalk.gray('ID:'), store.id],
      [chalk.gray('Name:'), chalk.bold(store.name)],
      [chalk.gray('Description:'), store.description ? store.description.slice(0, 100) : chalk.dim('N/A')],
      [chalk.gray('URL:'), chalk.hex('#6366f1')(store.url)],
      [chalk.gray('Status:'), store.status === 'active' ? chalk.green('✓ Active') : chalk.yellow(store.status)],
      [chalk.gray('Logo:'), store.logo_url ? chalk.dim(store.logo_url.slice(0, 55)) : chalk.dim('N/A')]
    );

    console.log(table.toString());

    if (store.social_links) {
      const socials = Object.entries(store.social_links).filter(([, v]) => v);
      if (socials.length > 0) {
        console.log(chalk.cyan('\n🌐 Social Links:\n'));
        socials.forEach(([platform, url]) => {
          console.log(`  ${chalk.bold(platform.padEnd(12))} ${chalk.dim(String(url))}`);
        });
        console.log('');
      }
    }

    if (store.appearance) {
      const a = store.appearance;
      console.log(chalk.cyan('\n🎨 Appearance:\n'));
      console.log(`  Theme:          ${chalk.white(a.theme?.label || a.theme?.value || 'N/A')}`);
      console.log(`  Primary Font:   ${chalk.white(a.font?.primary?.display_name || 'N/A')}`);
      console.log(`  Primary Color:  ${chalk.hex(a.color?.primary?.hex || '#ffffff')(a.color?.primary?.hex || 'N/A')}`);
      console.log(`  Products/Row:   ${chalk.white(a.products_per_row || 'N/A')}`);
      console.log('');
    }
  } catch (error: any) {
    spinner.fail('Failed to fetch store info');
    console.log(chalk.red(error.message));
  }
}

#!/usr/bin/env node

import chalk from 'chalk';
import readline from 'readline';
import { getConfig } from '../utils/config.js';
import { Chariow } from '../../index.js';
import type { Store } from '../../types/product.js';
import type { Sale } from '../../modules/sales.js';

// ─── Palette ───────────────────────────────────────────────────────────────
const C = {
  primary:  chalk.hex('#6366f1'),
  success:  chalk.hex('#10b981'),
  warning:  chalk.hex('#f59e0b'),
  error:    chalk.hex('#ef4444'),
  info:     chalk.hex('#3b82f6'),
  border:   chalk.hex('#334155'),
  text:     chalk.hex('#94a3b8'),
  accent:   chalk.hex('#8b5cf6'),
  white:    chalk.white,
  dim:      chalk.dim,
  bold:     chalk.bold,
  cyan:     chalk.cyan,
};

const W = 76; // total inner width of box

function pad(s: string, n: number): string {
  const vis = stripAnsi(s);
  return vis.length >= n ? s : s + ' '.repeat(n - vis.length);
}
function rpad(s: string, n: number): string {
  const vis = stripAnsi(s);
  return vis.length >= n ? s : ' '.repeat(n - vis.length) + s;
}
function stripAnsi(s: string): string {
  return s.replace(/\x1B\[[0-9;]*m/g, '');
}
function truncate(s: string, max: number): string {
  if (!s) return '';
  return s.length <= max ? s : s.slice(0, max - 1) + '…';
}
function center(s: string, width: number): string {
  const vis = stripAnsi(s);
  const left = Math.floor((width - vis.length) / 2);
  const right = width - vis.length - left;
  return ' '.repeat(Math.max(0, left)) + s + ' '.repeat(Math.max(0, right));
}
function row(content: string): string {
  const vis = stripAnsi(content);
  const pad = W - vis.length;
  return C.border('│') + content + ' '.repeat(Math.max(0, pad)) + C.border('│');
}
function divider(l = '├', m = '─', r = '┤'): string {
  return C.border(l + m.repeat(W) + r);
}
function top(): string    { return C.border('┌' + '─'.repeat(W) + '┐'); }
function bottom(): string { return C.border('└' + '─'.repeat(W) + '┘'); }

// ─── State ─────────────────────────────────────────────────────────────────
type Tab = 'products' | 'sales' | 'store' | 'config';

interface DashState {
  tab: Tab;
  products: any[];
  sales: Sale[];
  store: Store | null;
  selIdx: number;
  loading: boolean;
  loadingMsg: string;
  err: string | null;
  lastSync: Date;
  wsActive: boolean;
  wsTimer: ReturnType<typeof setInterval> | null;
}

const TABS: Tab[] = ['products', 'sales', 'store', 'config'];
const TAB_LABELS: Record<Tab, string> = {
  products: '📦 Products',
  sales:    '🛒 Sales',
  store:    '🏪 Store',
  config:   '⚙️  Config',
};

// ─── Helpers ───────────────────────────────────────────────────────────────
function fmtPrice(product: any): string {
  const p = product.pricing?.current_price;
  if (!p) return 'Free';
  if (p.formatted) return p.formatted;
  if (p.value) {
    const cur = p.currency || 'XAF';
    const sym = cur === 'USD' ? '$' : cur === 'EUR' ? '€' : cur === 'XAF' ? 'FCFA' : cur;
    return `${sym} ${p.value.toLocaleString()}`;
  }
  return 'Free';
}
function priceVal(product: any): number {
  const p = product.pricing?.current_price;
  if (!p) return 0;
  return typeof p.value === 'number' ? p.value : typeof p.amount === 'number' ? p.amount : 0;
}
function salesCount(p: any): number {
  if (typeof p.sales_count === 'number') return p.sales_count;
  if (typeof p.sales === 'number') return p.sales;
  return 0;
}
function bar(val: number, max: number, width = 24): string {
  const pct = Math.min(1, Math.max(0, val / (max || 1)));
  const filled = Math.round(width * pct);
  return C.success('█'.repeat(filled)) + C.text('░'.repeat(width - filled));
}

