import { ChariowClient } from "../client.js"

export interface MarketplaceStore {
  id: string
  name: string
  slug: string
  description: string | null
  logo_url: string | null
  url: string
  status: string
  products_count?: number
  category?: string
  rating?: { average: number; count: number }
  social_links?: Record<string, string | null>
  appearance?: {
    theme?: { value: string; label: string }
    color?: { primary?: { hex: string }; contrast?: { hex: string } }
  }
}

export interface MarketplaceStoresResponse {
  data: MarketplaceStore[]
  pagination?: {
    next_cursor: string | null
    has_more_pages: boolean
    count: number
  }
}

export interface MarketplaceProduct {
  id: string
  name: string
  description?: string
  status: string
  type?: string
  pricing?: {
    current_price?: { value?: number; formatted?: string; currency?: string }
  }
  rating?: { average: number; count: number }
  sales_count?: number
  category?: { value: string; label: string }
}

export class MarketplaceAPI {
  client: ChariowClient

  constructor(client: ChariowClient) {
    this.client = client
  }

  async listStores(params: { per_page?: number; cursor?: string; search?: string } = {}): Promise<MarketplaceStoresResponse> {
    const p = new URLSearchParams()
    if (params.per_page) p.append("per_page", String(params.per_page))
    if (params.cursor)   p.append("cursor", params.cursor)
    if (params.search)   p.append("search", params.search)
    const qs = p.toString()

    try {
      const res = await this.client.request<MarketplaceStoresResponse>(`/marketplace/stores${qs ? `?${qs}` : ""}`)
      if (Array.isArray(res)) {
        return { data: res as MarketplaceStore[], pagination: { next_cursor: null, has_more_pages: false, count: (res as any[]).length } }
      }
      return res
    } catch {
      // fallback to /stores
      try {
        const res2 = await this.client.request<MarketplaceStoresResponse>(`/stores${qs ? `?${qs}` : ""}`)
        if (Array.isArray(res2)) {
          return { data: res2 as MarketplaceStore[], pagination: { next_cursor: null, has_more_pages: false, count: (res2 as any[]).length } }
        }
        return res2
      } catch {
        return { data: [], pagination: { next_cursor: null, has_more_pages: false, count: 0 } }
      }
    }
  }

  async getStore(slugOrId: string): Promise<MarketplaceStore> {
    try {
      return await this.client.request<MarketplaceStore>(`/marketplace/stores/${slugOrId}`)
    } catch {
      return await this.client.request<MarketplaceStore>(`/stores/${slugOrId}`)
    }
  }

  async getStoreProducts(slugOrId: string, params: { per_page?: number } = {}): Promise<MarketplaceProduct[]> {
    const p = new URLSearchParams()
    if (params.per_page) p.append("per_page", String(params.per_page))
    const qs = p.toString()

    try {
      const res = await this.client.request<any>(`/marketplace/stores/${slugOrId}/products${qs ? `?${qs}` : ""}`)
      if (Array.isArray(res)) return res
      if (res?.data && Array.isArray(res.data)) return res.data
      return []
    } catch {
      try {
        const res2 = await this.client.request<any>(`/stores/${slugOrId}/products${qs ? `?${qs}` : ""}`)
        if (Array.isArray(res2)) return res2
        if (res2?.data && Array.isArray(res2.data)) return res2.data
        return []
      } catch {
        return []
      }
    }
  }
}

import { Chariow } from '../../index.js';
import { getConfig } from '../utils/config.js';
import chalk from 'chalk';
import Table from 'cli-table3';
import ora from 'ora';
import inquirer from 'inquirer';

const C = {
  primary: chalk.hex('#6366f1'),
  success: chalk.hex('#10b981'),
  warning: chalk.hex('#f59e0b'),
  error:   chalk.hex('#ef4444'),
  info:    chalk.hex('#3b82f6'),
  accent:  chalk.hex('#8b5cf6'),
  text:    chalk.hex('#94a3b8'),
  dim:     chalk.dim,
  bold:    chalk.bold,
  cyan:    chalk.cyan,
};

function requireApiKey(): { apiKey: string } {
  const config = getConfig();
  if (!config?.apiKey) {
    console.log(C.error('\n❌ No API key found. Run: chariow config --set <token>\n'));
    process.exit(1);
  }
  return config as { apiKey: string };
}

export async function productsCommand(options: any) {
  const config = requireApiKey();
  const client = new Chariow(config.apiKey);

  if (options.list) {
    await listProducts(client, options);
  } else if (options.get) {
    await getProduct(client, options.get);
  } else if (options.search) {
    await searchProducts(client, options.search);
  } else if (options.create) {
    await createProduct(client);
  } else if (options.publish) {
    await publishProduct(client, options.publish, 'published');
  } else if (options.unpublish) {
    await publishProduct(client, options.unpublish, 'draft');
  } else if (options.delete) {
    await deleteProduct(client, options.delete);
  } else if (options.stats) {
    await showStats(client);
  } else {
    console.log(C.warning('\nUsage:\n'));
    const cmds = [
      ['--list',              'List all products'],
      ['--get <id>',          'View product details'],
      ['--search <term>',     'Search products'],
      ['--create',            'Create a new product (interactive)'],
      ['--publish <id>',      'Publish a product'],
      ['--unpublish <id>',    'Unpublish a product (back to draft)'],
      ['--delete <id>',       'Delete a product'],
      ['--stats',             'Show statistics'],
    ];
    cmds.forEach(([cmd, desc]) => {
      console.log(`  ${C.accent('chariow products ' + cmd.padEnd(22))} ${C.text(desc)}`);
    });
    console.log('');
  }
}

// ─── List ─────────────────────────────────────────────────────────────────
async function listProducts(client: Chariow, options: any) {
  const limit = options.limit ? parseInt(options.limit) : 50;
  const spinner = ora('Fetching products...').start();
  try {
    const response = await client.products.list({ per_page: limit, status: options.status });
    spinner.succeed(`Found ${response.data.length} product(s)\n`);

    if (response.data.length === 0) {
      console.log(C.dim('No products found.\n'));
      return;
    }

    const table = new Table({
      head: [
        C.cyan('ID'), C.cyan('Name'), C.cyan('Type'),
        C.cyan('Status'), C.cyan('Price'), C.cyan('Sales'),
      ],
      colWidths: [28, 36, 10, 14, 16, 8],
    });

    response.data.forEach(p => {
      table.push([
        C.dim(p.id.slice(0, 26)),
        p.name.slice(0, 34),
        C.text(p.type || '—'),
        p.status === 'published' ? C.success('✓ Published') : C.warning('○ Draft'),
        C.success(p.pricing?.current_price?.formatted || 'Free'),
        C.accent(String(p.sales_count ?? '—')),
      ]);
    });

    console.log(table.toString());

    const published = response.data.filter(p => p.status === 'published').length;
    console.log(C.text(`\n  Published: ${C.success(String(published))}  Draft: ${C.warning(String(response.data.length - published))}\n`));
  } catch (error: any) {
    spinner.fail('Failed to fetch products');
    console.log(C.error(error.message));
  }
}

// ─── Get ──────────────────────────────────────────────────────────────────
async function getProduct(client: Chariow, id: string) {
  const spinner = ora(`Fetching product ${id}...`).start();
  try {
    const p = await client.products.get(id);
    spinner.succeed();

    console.log('\n' + C.bold.cyan('📦 Product Details\n'));

    const table = new Table({ colWidths: [22, 58] });
    const row = (k: string, v: string) => table.push([C.text(k + ':'), v]);

    row('ID',          C.dim(p.id));
    row('Name',        C.bold(p.name));
    row('Type',        p.type || '—');
    row('Category',    p.category?.label || 'Uncategorized');
    row('Status',      p.status === 'published' ? C.success('✓ Published') : C.warning('○ Draft'));
    row('Price',       C.success(p.pricing?.current_price?.formatted || 'Free'));
    row('Sales',       C.accent(String(p.sales_count ?? '0')));
    row('Rating',      p.rating?.average ? C.warning(`${p.rating.average} ★`) + C.dim(` (${p.rating.count} reviews)`) : 'No ratings');
    row('On Sale Until', p.on_sale_until || '—');
    row('URL',         C.primary(`https://app.chariow.com/products/${p.id}`));

    console.log(table.toString());

    if (p.description) {
      const clean = p.description.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
      console.log('\n' + C.cyan('Description:'));
      console.log(C.text(clean.slice(0, 400)) + (clean.length > 400 ? C.dim('…') : '') + '\n');
    }
  } catch (error: any) {
    spinner.fail('Product not found');
    console.log(C.error(error.message));
  }
}

// ─── Search ───────────────────────────────────────────────────────────────
async function searchProducts(client: Chariow, term: string) {
  const spinner = ora(`Searching for "${term}"...`).start();
  try {
    const results = await client.products.search(term);
    spinner.succeed(`Found ${results.length} product(s) matching "${term}"\n`);

    if (results.length === 0) {
      console.log(C.dim('No results.\n'));
      return;
    }

    const table = new Table({
      head: [C.cyan('Name'), C.cyan('Status'), C.cyan('Price'), C.cyan('Sales')],
      colWidths: [42, 14, 16, 8],
    });

    results.forEach(p => {
      table.push([
        p.name.slice(0, 40),
        p.status === 'published' ? C.success('✓ Published') : C.warning('○ Draft'),
        C.success(p.pricing?.current_price?.formatted || 'Free'),
        String(p.sales_count ?? '—'),
      ]);
    });

    console.log(table.toString());
    console.log('');
  } catch (error: any) {
    spinner.fail('Search failed');
    console.log(C.error(error.message));
  }
}

// ─── Create ───────────────────────────────────────────────────────────────
async function createProduct(client: Chariow) {
  console.log('\n' + C.primary.bold('╔══════════════════════════════════════════════╗'));
  console.log(C.primary.bold('║       📦  CREATE NEW PRODUCT                 ║'));
  console.log(C.primary.bold('╚══════════════════════════════════════════════╝\n'));
  console.log(C.text('Fill in the details below. Press Ctrl+C to cancel.\n'));

  const answers = await inquirer.prompt([
    {
      type: 'input',
      name: 'name',
      message: '📝 Product name:',
      validate: (v: string) => v.trim().length >= 2 ? true : 'Name must be at least 2 characters',
    },
    {
      type: 'list',
      name: 'type',
      message: '📂 Product type:',
      choices: [
        { name: '💾 Digital  — downloadable file, software, ebook', value: 'digital' },
        { name: '📦 Physical — shipped product', value: 'physical' },
        { name: '🛠  Service  — consulting, freelance work', value: 'service' },
        { name: '📚 Course   — online course or training', value: 'course' },
        { name: '🔑 License  — license key / subscription', value: 'license' },
      ],
    },
    {
      type: 'list',
      name: 'category',
      message: '🏷  Category:',
      choices: [
        { name: '🤖 AI & Machine Learning', value: 'ai_ml' },
        { name: '🌐 Web Development',        value: 'web_dev' },
        { name: '📱 Mobile Apps',             value: 'mobile' },
        { name: '☁️  DevOps & Cloud',         value: 'devops' },
        { name: '🔒 Cybersecurity',           value: 'security' },
        { name: '📊 Data Science',            value: 'data_science' },
        { name: '🎨 Design & UX',             value: 'design' },
        { name: '📣 Marketing & SEO',          value: 'marketing' },
        { name: '🛒 E-commerce',              value: 'ecommerce' },
        { name: '⚡ Productivity',            value: 'productivity' },
        { name: '🎓 Education',               value: 'education' },
        { name: '🎮 Gaming',                  value: 'gaming' },
        { name: '💼 Business',                value: 'business' },
        { name: '📦 Other',                   value: 'other' },
      ],
    },
    {
      type: 'editor',
      name: 'description',
      message: '📄 Description (opens editor — save & close to continue):',
    },
    {
      type: 'list',
      name: 'pricingType',
      message: '💰 Pricing type:',
      choices: [
        { name: '💵 Fixed price', value: 'fixed' },
        { name: '🆓 Free',        value: 'free' },
        { name: '🎯 Pay what you want', value: 'pwyw' },
      ],
    },
    {
      type: 'number',
      name: 'price',
      message: '💵 Price (number):',
      when: (ans: any) => ans.pricingType === 'fixed' || ans.pricingType === 'pwyw',
      validate: (v: number) => (v >= 0 ? true : 'Price must be >= 0'),
    },
    {
      type: 'list',
      name: 'currency',
      message: '💱 Currency:',
      when: (ans: any) => ans.pricingType !== 'free',
      choices: ['USD', 'EUR', 'GBP', 'XAF', 'NGN', 'GHS', 'KES', 'MAD'],
      default: 'USD',
    },
    {
      type: 'list',
      name: 'status',
      message: '🚀 Initial status:',
      choices: [
        { name: '○ Draft   — save and publish later', value: 'draft' },
        { name: '● Publish — make it live immediately', value: 'published' },
      ],
    },
    {
      type: 'input',
      name: 'seoTitle',
      message: '🔍 SEO title (optional, Enter to skip):',
    },
    {
      type: 'input',
      name: 'seoDescription',
      message: '🔍 SEO description (optional, Enter to skip):',
    },
    {
      type: 'confirm',
      name: 'confirm',
      message: (ans: any) => `\nCreate "${ans.name}" as ${ans.status}?`,
      default: true,
    },
  ]);

  if (!answers.confirm) {
    console.log(C.warning('\n⚠ Cancelled — product not created.\n'));
    return;
  }

  const spinner = ora('Creating product...').start();

  try {
    const body: Record<string, any> = {
      name: answers.name.trim(),
      description: answers.description?.trim() || '',
      type: answers.type,
      category: answers.category,
      status: answers.status,
      pricing: {
        type: answers.pricingType,
        ...(answers.pricingType !== 'free' && answers.price != null
          ? {
              price: {
                value: Number(answers.price),
                currency: answers.currency || 'USD',
              },
            }
          : {}),
      },
    };

    if (answers.seoTitle || answers.seoDescription) {
      body.seo = {
        title: answers.seoTitle || '',
        description: answers.seoDescription || '',
        keywords: [],
      };
    }

    const product = await client.products.create(body);
    spinner.succeed(C.success('Product created successfully!\n'));

    console.log(`  ${C.text('ID:')}     ${C.dim(product.id)}`);
    console.log(`  ${C.text('Name:')}   ${C.bold(product.name)}`);
    console.log(`  ${C.text('Status:')} ${product.status === 'published' ? C.success('● Published') : C.warning('○ Draft')}`);
    console.log(`  ${C.text('URL:')}    ${C.primary(`https://app.chariow.com/products/${product.id}`)}`);
    console.log('');
  } catch (error: any) {
    spinner.fail('Failed to create product');
    console.log(C.error('\n' + error.message + '\n'));
  }
}

// ─── Publish / Unpublish ──────────────────────────────────────────────────
async function publishProduct(client: Chariow, id: string, status: 'published' | 'draft') {
  const action = status === 'published' ? 'Publishing' : 'Unpublishing';
  const spinner = ora(`${action} product ${id}...`).start();
  try {
    const product = await client.products.update(id, { status });
    const label = status === 'published' ? C.success('✓ Published') : C.warning('○ Draft');
    spinner.succeed(`${product.name} — ${label}\n`);
    console.log(`  ${C.text('URL:')} ${C.primary(`https://app.chariow.com/products/${product.id}`)}\n`);
  } catch (error: any) {
    spinner.fail(`Failed to ${action.toLowerCase()} product`);
    console.log(C.error(error.message));
  }
}

// ─── Delete ───────────────────────────────────────────────────────────────
async function deleteProduct(client: Chariow, id: string) {
  const { confirm } = await inquirer.prompt([
    {
      type: 'confirm',
      name: 'confirm',
      message: C.error(`⚠ Delete product ${id}? This cannot be undone.`),
      default: false,
    },
  ]);

  if (!confirm) {
    console.log(C.warning('\n⚠ Cancelled.\n'));
    return;
  }

  const spinner = ora('Deleting product...').start();
  try {
    await client.products.delete(id);
    spinner.succeed(C.success('Product deleted successfully.\n'));
  } catch (error: any) {
    spinner.fail('Failed to delete product');
    console.log(C.error(error.message));
  }
}

// ─── Stats ────────────────────────────────────────────────────────────────
async function showStats(client: Chariow) {
  const spinner = ora('Computing statistics...').start();
  try {
    const response = await client.products.list({ per_page: 100 });
    const products = response.data;

    const published  = products.filter(p => p.status === 'published');
    const drafts     = products.filter(p => p.status !== 'published');
    const totalSales = products.reduce((s, p) => s + (p.sales_count ?? 0), 0);
    const totalRev   = products.reduce((s, p) => {
      const val = p.pricing?.current_price?.value ?? 0;
      return s + val * (p.sales_count ?? 0);
    }, 0);
    const avgRating  = products.length
      ? products.reduce((s, p) => s + (p.rating?.average ?? 0), 0) / products.length
      : 0;

    const byType: Record<string, number> = {};
    products.forEach(p => {
      byType[p.type || 'unknown'] = (byType[p.type || 'unknown'] || 0) + 1;
    });

    spinner.succeed('Product statistics\n');

    console.log(C.primary.bold('\n📊  PRODUCT STATISTICS\n'));
    console.log(`  ${C.cyan('Total products:')}   ${C.bold(String(products.length))}`);
    console.log(`  ${C.cyan('Published:')}        ${C.success(String(published.length))}`);
    console.log(`  ${C.cyan('Draft:')}            ${C.warning(String(drafts.length))}`);
    console.log(`  ${C.cyan('Total Sales:')}      ${C.accent(String(totalSales))}`);
    console.log(`  ${C.cyan('Est. Revenue:')}     ${C.success(new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(totalRev))}`);
    console.log(`  ${C.cyan('Avg Rating:')}       ${avgRating ? C.warning(avgRating.toFixed(2) + ' ★') : C.dim('N/A')}`);

    if (Object.keys(byType).length > 0) {
      console.log('\n  ' + C.cyan('By type:'));
      Object.entries(byType).forEach(([type, count]) => {
        console.log(`    ${C.text((type + ':').padEnd(14))} ${C.bold(String(count))}`);
      });
    }

    console.log('');
  } catch (error: any) {
    spinner.fail('Failed to load statistics');
    console.log(C.error(error.message));
  }
}

import chalk from 'chalk';
import ora from 'ora';
import inquirer from 'inquirer';
import Table from 'cli-table3';
import { getConfig } from '../utils/config.js';
import { Chariow } from '../../index.js';
import type { MarketplaceStore, MarketplaceProduct } from '../../modules/marketplace.js';
import { exec } from 'child_process';
import { promisify } from 'util';

const execAsync = promisify(exec);

const C = {
  primary: chalk.hex('#6366f1'),
  success: chalk.hex('#10b981'),
  warning: chalk.hex('#f59e0b'),
  error:   chalk.hex('#ef4444'),
  info:    chalk.hex('#3b82f6'),
  accent:  chalk.hex('#8b5cf6'),
  text:    chalk.hex('#94a3b8'),
  dim:     chalk.dim,
  bold:    chalk.bold,
  cyan:    chalk.cyan,
  white:   chalk.white,
};

function getClient(): Chariow | null {
  const config = getConfig();
  if (config?.apiKey) return new Chariow(config.apiKey);
  return null;
}

// ─── Entry ────────────────────────────────────────────────────────────────
export async function exploreCommand(options: any) {
  console.log('\n' + C.accent.bold('╔══════════════════════════════════════════════════════════╗'));
  console.log(C.accent.bold('║   🔍  CHARIOW MARKETPLACE  —  Explore All Stores         ║'));
  console.log(C.accent.bold('╚══════════════════════════════════════════════════════════╝\n'));

  if (options.search) {
    await searchStores(options.search);
  } else if (options.store) {
    await viewStore(options.store);
  } else if (options.top) {
    await showTopStores();
  } else if (options.products) {
    await browseAllProducts(options.products === true ? undefined : options.products);
  } else {
    await interactiveExplore();
  }
}

// ─── Interactive main menu ────────────────────────────────────────────────
async function interactiveExplore() {
  let running = true;

  while (running) {
    const { action } = await inquirer.prompt([
      {
        type: 'list',
        name: 'action',
        message: C.accent('What would you like to explore?'),
        pageSize: 12,
        choices: [
          { name: '🏪 Browse all stores',              value: 'stores' },
          { name: '🔍 Search stores by name',          value: 'search_stores' },
          { name: '📦 Browse all products',            value: 'products' },
          { name: '⭐ Top rated stores',               value: 'top' },
          { name: '🏷  Filter products by category',   value: 'category' },
          { name: '💰 Filter products by price',       value: 'price' },
          { name: '🌐 Open Chariow in browser',        value: 'browser' },
          new inquirer.Separator(),
          { name: '◀  Exit explore',                   value: 'back' },
        ],
      },
    ]);

    switch (action) {
      case 'stores':        await browseStores(); break;
      case 'search_stores': await searchStoresInteractive(); break;
      case 'products':      await browseAllProducts(); break;
      case 'top':           await showTopStores(); break;
      case 'category':      await browseByCategory(); break;
      case 'price':         await browseByPrice(); break;
      case 'browser':       await openBrowser('https://chariow.com'); break;
      case 'back':          running = false; break;
    }
  }
}

// ─── Browse stores ────────────────────────────────────────────────────────
async function browseStores(search?: string) {
  const spinner = ora('Loading Chariow stores...').start();
  const client = getClient();

  try {
    if (!client) {
      spinner.fail('API key required. Run: chariow config --set <token>');
      return;
    }

    const resp = await client.marketplace.listStores({ per_page: 50, search });
    const stores = resp.data;

    if (stores.length === 0) {
      spinner.warn('No stores found.');
      return;
    }

    spinner.succeed(`Found ${stores.length} store(s)\n`);

    const table = new Table({
      head: [C.cyan('#'), C.cyan('Store Name'), C.cyan('Status'), C.cyan('Products'), C.cyan('URL')],
      colWidths: [4, 32, 12, 10, 36],
    });

    stores.forEach((s, i) => {
      table.push([
        C.dim(String(i + 1)),
        C.bold(s.name.slice(0, 30)),
        s.status === 'active' ? C.success('● Active') : C.warning(s.status || '—'),
        C.accent(s.products_count != null ? String(s.products_count) : '—'),
        C.text((s.url || '—').slice(0, 34)),
      ]);
    });

    console.log(table.toString());

    const { pick } = await inquirer.prompt([
      {
        type: 'confirm',
        name: 'pick',
        message: 'View a store in detail?',
        default: true,
      },
    ]);

    if (pick) {
      const { storeId } = await inquirer.prompt([
        {
          type: 'list',
          name: 'storeId',
          message: 'Select a store:',
          pageSize: 15,
          choices: stores.map((s, i) => ({
            name: `${i + 1}. ${s.name}  ${C.text(s.url || '')}`,
            value: s.slug || s.id,
          })),
        },
      ]);

      await viewStore(storeId);
    }
  } catch (err: any) {
    spinner.fail('Failed to load stores');
    console.log(C.error(err.message));
  }
}

// ─── View single store ────────────────────────────────────────────────────
async function viewStore(slugOrId: string) {
  const client = getClient();
  if (!client) {
    console.log(C.error('\nAPI key required. Run: chariow config --set <token>\n'));
    return;
  }

  const spinner = ora(`Loading store "${slugOrId}"...`).start();

  try {
    const store = await client.marketplace.getStore(slugOrId);
    spinner.succeed(`Store: ${store.name}\n`);

    printStoreBanner(store);

    // Load store products
    const prodSpinner = ora('Loading store products...').start();
    const products = await client.marketplace.getStoreProducts(slugOrId, { per_page: 50 });
    prodSpinner.succeed(`${products.length} product(s) in this store\n`);

    if (products.length > 0) {
      printProductsTable(products);
    }

    const { action } = await inquirer.prompt([
      {
        type: 'list',
        name: 'action',
        message: 'What next?',
        choices: [
          ...(products.length > 0 ? [{ name: '📦 View a product', value: 'product' }] : []),
          { name: '🌐 Open store in browser', value: 'browser' },
          { name: '◀  Back',                  value: 'back' },
        ],
      },
    ]);

    if (action === 'browser') {
      await openBrowser(store.url || `https://chariow.com/store/${slugOrId}`);
    } else if (action === 'product' && products.length > 0) {
      const { pid } = await inquirer.prompt([
        {
          type: 'list',
          name: 'pid',
          message: 'Select a product:',
          pageSize: 15,
          choices: products.map(p => ({
            name: `${p.name}  ${C.success(p.pricing?.current_price?.formatted || 'Free')}`,
            value: p.id,
          })),
        },
      ]);
      await viewProduct(client, pid);
    }
  } catch (err: any) {
    spinner.fail('Failed to load store');
    console.log(C.error(err.message));
  }
}

// ─── View product ─────────────────────────────────────────────────────────
async function viewProduct(client: Chariow, id: string) {
  const spinner = ora('Loading product...').start();
  try {
    const p = await client.products.get(id);
    spinner.succeed();

    console.log('\n' + C.bold.cyan('📦 PRODUCT DETAILS\n'));

    const table = new Table({ colWidths: [22, 58] });
    const r = (k: string, v: string) => table.push([C.text(k + ':'), v]);

    r('Name',       C.bold(p.name));
    r('ID',         C.dim(p.id));
    r('Type',       p.type || '—');
    r('Category',   p.category?.label || 'Uncategorized');
    r('Status',     p.status === 'published' ? C.success('● Published') : C.warning('○ Draft'));
    r('Price',      C.success(p.pricing?.current_price?.formatted || 'Free'));
    r('Rating',     p.rating?.average ? C.warning(`${p.rating.average} ★`) + C.dim(` (${p.rating.count} reviews)`) : 'No ratings');
    r('Sales',      String(p.sales_count ?? '—'));
    r('URL',        C.primary(`https://app.chariow.com/products/${p.id}`));

    console.log(table.toString());

    if (p.description) {
      const clean = p.description.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
      console.log('\n' + C.cyan('Description:'));
      console.log(C.text(clean.slice(0, 500)) + '\n');
    }

    const { open } = await inquirer.prompt([
      {
        type: 'confirm',
        name: 'open',
        message: 'Open in browser?',
        default: false,
      },
    ]);
    if (open) await openBrowser(`https://app.chariow.com/products/${p.id}`);
  } catch (err: any) {
    spinner.fail('Failed to load product');
    console.log(C.error(err.message));
  }
}

// ─── Browse all products ──────────────────────────────────────────────────
async function browseAllProducts(category?: string) {
