import { ChariowClient } from "../client.js"

export type WebhookEvent =
  | 'product.created'
  | 'product.updated'
  | 'product.deleted'
  | 'product.published'
  | 'sale.created'
  | 'sale.completed'
  | 'sale.refunded'
  | 'store.updated'
  | 'payment.succeeded'
  | 'payment.failed'

export interface Webhook {
  id: string
  url: string
  events: WebhookEvent[]
  secret?: string
  status: 'active' | 'inactive'
  created_at: string
  updated_at?: string
  last_triggered_at?: string | null
  failure_count?: number
}

export interface WebhookDelivery {
  id: string
  webhook_id: string
  event: WebhookEvent
  status: 'success' | 'failed' | 'pending'
  response_code?: number
  payload: Record<string, any>
  created_at: string
}

export interface CreateWebhookBody {
  url: string
  events: WebhookEvent[]
  secret?: string
}

export class HooksAPI {
  client: ChariowClient

  constructor(client: ChariowClient) {
    this.client = client
  }

  async list(): Promise<Webhook[]> {
    const res = await this.client.request<Webhook[] | { data: Webhook[] }>('/webhooks')
    return Array.isArray(res) ? res : (res as any).data ?? []
  }

  async get(id: string): Promise<Webhook> {
    return this.client.request<Webhook>(`/webhooks/${id}`)
  }

  async create(body: CreateWebhookBody): Promise<Webhook> {
    return this.client.request<Webhook>('/webhooks', {
      method: 'POST',
      body: JSON.stringify(body),
    })
  }

  async update(id: string, body: Partial<CreateWebhookBody> & { status?: 'active' | 'inactive' }): Promise<Webhook> {
    return this.client.request<Webhook>(`/webhooks/${id}`, {
      method: 'PUT',
      body: JSON.stringify(body),
    })
  }

  async delete(id: string): Promise<void> {
    return this.client.request<void>(`/webhooks/${id}`, { method: 'DELETE' })
  }

  async test(id: string, event?: WebhookEvent): Promise<{ success: boolean; response_code?: number; message?: string }> {
    return this.client.request(`/webhooks/${id}/test`, {
      method: 'POST',
      body: JSON.stringify({ event: event ?? 'product.created' }),
    })
  }

  async deliveries(id: string): Promise<WebhookDelivery[]> {
    const res = await this.client.request<WebhookDelivery[] | { data: WebhookDelivery[] }>(`/webhooks/${id}/deliveries`)
    return Array.isArray(res) ? res : (res as any).data ?? []
  }
}

import { ChariowClient } from "../client.js"

export interface DomainRecord {
  id: string
  domain: string
  type: 'custom' | 'subdomain'
  status: 'pending' | 'active' | 'failed' | 'inactive'
  ssl_status?: 'pending' | 'active' | 'failed'
  dns_records?: DnsRecord[]
  created_at: string
  verified_at?: string | null
}

export interface DnsRecord {
  type: 'CNAME' | 'A' | 'TXT'
  name: string
  value: string
  ttl?: number
}

export interface AddDomainBody {
  domain: string
}

export class DnsAPI {
  client: ChariowClient

  constructor(client: ChariowClient) {
    this.client = client
  }

  async list(): Promise<DomainRecord[]> {
    const res = await this.client.request<DomainRecord[] | { data: DomainRecord[] }>('/domains')
    return Array.isArray(res) ? res : (res as any).data ?? []
  }

  async get(id: string): Promise<DomainRecord> {
    return this.client.request<DomainRecord>(`/domains/${id}`)
  }

  async add(body: AddDomainBody): Promise<DomainRecord> {
    return this.client.request<DomainRecord>('/domains', {
      method: 'POST',
      body: JSON.stringify(body),
    })
  }

  async verify(id: string): Promise<DomainRecord> {
    return this.client.request<DomainRecord>(`/domains/${id}/verify`, {
      method: 'POST',
    })
  }

  async remove(id: string): Promise<void> {
    return this.client.request<void>(`/domains/${id}`, { method: 'DELETE' })
  }

  async setDefault(id: string): Promise<DomainRecord> {
    return this.client.request<DomainRecord>(`/domains/${id}/default`, {
      method: 'POST',
    })
  }
}

import { ChariowClient } from "../client.js"

export interface PaymentMethod {
  type: 'card' | 'mobile_money' | 'bank_transfer' | 'crypto' | 'paypal'
  provider?: string
}

export interface CheckoutItem {
  product_id: string
  quantity?: number
}

export interface CreateCheckoutBody {
  items: CheckoutItem[]
  customer_email?: string
  customer_name?: string
  payment_method?: PaymentMethod
  currency?: string
