import chalk from 'chalk';
import { getConfig } from '../utils/config.js';
import { ChariowWebSocket } from '../services/websocket.js';

const C = {
  primary: chalk.hex('#6366f1'),
  success: chalk.hex('#10b981'),
  warning: chalk.hex('#f59e0b'),
  error:   chalk.hex('#ef4444'),
  accent:  chalk.hex('#8b5cf6'),
  text:    chalk.hex('#94a3b8'),
  dim:     chalk.dim,
  bold:    chalk.bold,
  cyan:    chalk.cyan,
};

function ts(): string {
  return chalk.dim(`[${new Date().toLocaleTimeString()}]`);
}

function printBanner() {
  console.log(C.primary.bold(`
╔══════════════════════════════════════════════════════════════╗
║   🔌  CHARIOW  WEBSOCKET  MONITOR  —  Live Event Stream     ║
╚══════════════════════════════════════════════════════════════╝
`));
}

export async function wsCommand(options: any) {
  const config = getConfig();
  if (!config?.apiKey) {
    console.log(C.error('\n❌ No API key found. Run: chariow config --set <token>\n'));
    process.exit(1);
  }

  printBanner();

  const events = options.events
    ? (options.events as string).split(',').map((e: string) => e.trim())
    : ['all'];

  console.log(C.text(`  Subscribing to events: `) + C.accent(events.join(', ')));
  console.log(C.dim('  Press Ctrl+C to disconnect\n'));

  const ws = new ChariowWebSocket(config.apiKey);

  let eventCount = 0;
  const startTime = Date.now();

  const logEvent = (label: string, color: (s: string) => string, data: any) => {
    eventCount++;
    const uptime = Math.floor((Date.now() - startTime) / 1000);
    console.log(`\n${ts()} ${color(`● ${label}`)}`);
    console.log(C.dim(`  Events received: ${eventCount}  │  Uptime: ${uptime}s`));
    try {
      const formatted = JSON.stringify(data, null, 2)
        .split('\n')
        .slice(0, 20)
        .map(l => '  ' + C.dim(l))
        .join('\n');
      console.log(formatted);
    } catch {
      console.log('  ' + C.dim(String(data)));
    }
  };

  // ─── Event listeners ────────────────────────────────────────────────────
  ws.on('connected', () => {
    console.log(C.success(`${ts()} ✓ Connected to Chariow WebSocket`));
    console.log(C.dim('  Waiting for events...\n'));

    // Subscribe channels based on options
    if (options.store || events.includes('all') || events.some((e: string) => e.startsWith('store'))) {
      ws.subscribeToStore();
      console.log(C.text(`  ${ts()} Subscribed to store events`));
    }

    if (options.product) {
      ws.subscribeToProduct(options.product);
      console.log(C.text(`  ${ts()} Subscribed to product ${options.product}`));
    }
  });

  ws.on('disconnected', () => {
    console.log(C.warning(`\n${ts()} ⚠ Disconnected from WebSocket`));
  });

  ws.on('error', (err: Error) => {
    console.log(C.error(`\n${ts()} ✗ WebSocket error: ${err.message}`));
  });

  ws.on('new_sale', (data: any) => {
    if (events.includes('all') || events.includes('sale') || events.includes('sale.created')) {
      logEvent('NEW SALE', C.success, data);
      if (data?.product_name) console.log(C.success(`  🛒 ${data.product_name}  →  ${data.amount} ${data.currency || ''}`));
    }
  });

  ws.on('product_updated', (data: any) => {
    if (events.includes('all') || events.includes('product') || events.includes('product.updated')) {
      logEvent('PRODUCT UPDATED', C.info, data);
    }
  });

  ws.on('stats_update', (data: any) => {
    if (events.includes('all') || events.includes('stats')) {
      logEvent('STATS UPDATE', C.accent, data);
    }
  });

  ws.on('notification', (data: any) => {
    if (events.includes('all') || events.includes('notification')) {
      logEvent('NOTIFICATION', C.warning, data);
      if (data?.message) console.log(C.warning(`  💬 ${data.message}`));
    }
  });

  ws.on('message', (msg: any) => {
    if (events.includes('all')) {
      logEvent(`RAW: ${msg.type || 'unknown'}`, C.text, msg.data ?? msg);
    }
  });

  // ─── Connect ────────────────────────────────────────────────────────────
  try {
    console.log(C.text(`${ts()} Connecting to wss://api.chariow.com/v1/ws...\n`));
    await ws.connect();
  } catch (err: any) {
    console.log(C.error(`\n❌ Connection failed: ${err.message}`));
    console.log(C.dim('  The WebSocket endpoint may not be available for your plan.\n'));
    process.exit(1);
  }

  // Keep alive
  process.on('SIGINT', () => {
    console.log(C.warning('\n\n👋 Disconnecting WebSocket...\n'));
    ws.disconnect();
    process.exit(0);
  });
}

import chalk from 'chalk';
import ora from 'ora';
import inquirer from 'inquirer';
import Table from 'cli-table3';
import { Chariow } from '../../index.js';
import { getConfig } from '../utils/config.js';
import type { WebhookEvent } from '../../modules/hooks.js';

const C = {
  primary: chalk.hex('#6366f1'),
  success: chalk.hex('#10b981'),
  warning: chalk.hex('#f59e0b'),
  error:   chalk.hex('#ef4444'),
  accent:  chalk.hex('#8b5cf6'),
  text:    chalk.hex('#94a3b8'),
  dim:     chalk.dim,
  bold:    chalk.bold,
  cyan:    chalk.cyan,
};

const ALL_EVENTS: WebhookEvent[] = [
  'product.created', 'product.updated', 'product.deleted', 'product.published',
  'sale.created', 'sale.completed', 'sale.refunded',
  'store.updated',
  'payment.succeeded', 'payment.failed',
];

function requireClient(): Chariow {
  const config = getConfig();
  if (!config?.apiKey) {
    console.log(C.error('\n❌ No API key. Run: chariow config --set <token>\n'));
    process.exit(1);
  }
  return new Chariow(config.apiKey);
}

export async function hooksCommand(options: any) {
  const client = requireClient();

  if (options.list || (!options.create && !options.delete && !options.test && !options.get && !options.deliveries)) {
    await listHooks(client);
  } else if (options.create) {
    await createHook(client);
  } else if (options.get) {
    await getHook(client, options.get);
  } else if (options.delete) {
    await deleteHook(client, options.delete);
  } else if (options.test) {
    await testHook(client, options.test);
  } else if (options.deliveries) {
    await showDeliveries(client, options.deliveries);
  }
}

// ─── List ─────────────────────────────────────────────────────────────────
async function listHooks(client: Chariow) {
  const spinner = ora('Fetching webhooks...').start();
  try {
    const hooks = await client.hooks.list();
    spinner.succeed(`Found ${hooks.length} webhook(s)\n`);

    if (hooks.length === 0) {
      console.log(C.dim('No webhooks configured. Create one with: chariow hooks --create\n'));
      return;
    }

    const table = new Table({
      head: [C.cyan('ID'), C.cyan('URL'), C.cyan('Events'), C.cyan('Status'), C.cyan('Last Triggered')],
      colWidths: [28, 34, 24, 10, 22],
    });

    hooks.forEach(h => {
      const evts = h.events.length <= 2
        ? h.events.join(', ')
        : `${h.events.slice(0, 2).join(', ')} +${h.events.length - 2}`;
      table.push([
        C.dim(h.id.slice(0, 26)),
        h.url.slice(0, 32),
        C.text(evts),
        h.status === 'active' ? C.success('● active') : C.warning('○ off'),
        h.last_triggered_at ? C.dim(new Date(h.last_triggered_at).toLocaleString()) : C.dim('—'),
      ]);
    });

    console.log(table.toString());
    console.log(C.dim('\n  Use: chariow hooks --test <id>  to test a webhook\n'));
  } catch (err: any) {
    spinner.fail('Failed to load webhooks');
    console.log(C.error(err.message));
  }
}

// ─── Get ──────────────────────────────────────────────────────────────────
async function getHook(client: Chariow, id: string) {
  const spinner = ora('Fetching webhook...').start();
  try {
    const h = await client.hooks.get(id);
    spinner.succeed();

    console.log('\n' + C.bold.cyan('🔗 Webhook Details\n'));
    const table = new Table({ colWidths: [20, 60] });
    table.push(
      [C.text('ID:'),              C.dim(h.id)],
      [C.text('URL:'),             C.primary(h.url)],
      [C.text('Status:'),          h.status === 'active' ? C.success('● active') : C.warning('○ inactive')],
      [C.text('Events:'),          h.events.join(', ')],
      [C.text('Failures:'),        String(h.failure_count ?? 0)],
      [C.text('Created:'),         new Date(h.created_at).toLocaleString()],
      [C.text('Last Triggered:'),  h.last_triggered_at ? new Date(h.last_triggered_at).toLocaleString() : '—'],
    );
    console.log(table.toString());
    console.log('');
  } catch (err: any) {
    spinner.fail('Webhook not found');
    console.log(C.error(err.message));
  }
}

// ─── Create ───────────────────────────────────────────────────────────────
async function createHook(client: Chariow) {
  console.log('\n' + C.primary.bold('🔗  CREATE WEBHOOK\n'));

  const answers = await inquirer.prompt([
    {
      type: 'input',
      name: 'url',
      message: '🌐 Endpoint URL (must be https://):',
      validate: (v: string) => {
        if (!v.startsWith('http')) return 'Must start with http:// or https://';
        return true;
      },
    },
    {
      type: 'checkbox',
      name: 'events',
      message: '📡 Select events to subscribe:',
      choices: ALL_EVENTS.map(e => ({ name: e, value: e, checked: e === 'sale.created' || e === 'payment.succeeded' })),
      validate: (v: string[]) => v.length > 0 ? true : 'Select at least one event',
    },
    {
      type: 'input',
      name: 'secret',
      message: '🔑 Webhook secret (optional — used to verify payload signature):',
    },
    {
      type: 'confirm',
      name: 'confirm',
      message: (a: any) => `\nCreate webhook for ${a.url}?`,
      default: true,
    },
  ]);

  if (!answers.confirm) {
    console.log(C.warning('\n⚠ Cancelled.\n'));
    return;
  }

  const spinner = ora('Creating webhook...').start();
  try {
    const hook = await client.hooks.create({
      url: answers.url,
      events: answers.events,
      secret: answers.secret?.trim() || undefined,
    });
    spinner.succeed(C.success('Webhook created!\n'));
    console.log(`  ID:     ${C.dim(hook.id)}`);
    console.log(`  URL:    ${C.primary(hook.url)}`);
    console.log(`  Events: ${C.text(hook.events.join(', '))}\n`);
  } catch (err: any) {
    spinner.fail('Failed to create webhook');
    console.log(C.error(err.message));
  }
}

// ─── Delete ───────────────────────────────────────────────────────────────
async function deleteHook(client: Chariow, id: string) {
  const { ok } = await inquirer.prompt([
    {
      type: 'confirm',
      name: 'ok',
      message: C.error(`⚠ Delete webhook ${id}?`),
      default: false,
    },
  ]);
  if (!ok) { console.log(C.warning('\n⚠ Cancelled.\n')); return; }

  const spinner = ora('Deleting webhook...').start();
  try {
    await client.hooks.delete(id);
    spinner.succeed(C.success('Webhook deleted.\n'));
  } catch (err: any) {
    spinner.fail('Failed to delete');
    console.log(C.error(err.message));
  }
}

// ─── Test ─────────────────────────────────────────────────────────────────
async function testHook(client: Chariow, id: string) {
  const { event } = await inquirer.prompt([
    {
      type: 'list',
      name: 'event',
      message: 'Select event to test:',
      choices: ALL_EVENTS,
      default: 'sale.created',
    },
  ]);

  const spinner = ora(`Sending test payload for ${event}...`).start();
  try {
    const result = await client.hooks.test(id, event as WebhookEvent);
    if (result?.success) {
      spinner.succeed(C.success(`Test delivered! Response: ${result.response_code ?? 200}\n`));
    } else {
      spinner.fail(C.warning(`Test failed: ${result?.message || 'Unknown error'}\n`));
    }
  } catch (err: any) {
    spinner.fail('Test failed');
    console.log(C.error(err.message));
  }
}

// ─── Deliveries ───────────────────────────────────────────────────────────
async function showDeliveries(client: Chariow, id: string) {
  const spinner = ora('Loading delivery history...').start();
  try {
    const deliveries = await client.hooks.deliveries(id);
    spinner.succeed(`${deliveries.length} delivery record(s)\n`);

    if (deliveries.length === 0) {
      console.log(C.dim('No deliveries yet.\n'));
      return;
    }

    const table = new Table({
      head: [C.cyan('Event'), C.cyan('Status'), C.cyan('Code'), C.cyan('Date')],
      colWidths: [22, 12, 8, 26],
    });

    deliveries.slice(0, 20).forEach(d => {
      table.push([
        C.text(d.event),
        d.status === 'success' ? C.success('✓ success') : C.error('✗ failed'),
        String(d.response_code ?? '—'),
        new Date(d.created_at).toLocaleString(),
      ]);
    });

    console.log(table.toString());
    console.log('');
  } catch (err: any) {
    spinner.fail('Failed to load deliveries');
    console.log(C.error(err.message));
  }
}

import chalk from 'chalk';
import ora from 'ora';
import inquirer from 'inquirer';
import Table from 'cli-table3';
import { Chariow } from '../../index.js';
import { getConfig } from '../utils/config.js';

const C = {
  primary: chalk.hex('#6366f1'),
  success: chalk.hex('#10b981'),
  warning: chalk.hex('#f59e0b'),
  error:   chalk.hex('#ef4444'),
  accent:  chalk.hex('#8b5cf6'),
  text:    chalk.hex('#94a3b8'),
  dim:     chalk.dim,
  bold:    chalk.bold,
  cyan:    chalk.cyan,
};

const STATUS_COLOR: Record<string, (s: string) => string> = {
  active:   C.success,
  pending:  C.warning,
  failed:   C.error,
  inactive: C.text,
};

function requireClient(): Chariow {
  const config = getConfig();
  if (!config?.apiKey) {
    console.log(C.error('\n❌ No API key. Run: chariow config --set <token>\n'));
    process.exit(1);
  }
  return new Chariow(config.apiKey);
}

export async function dnsCommand(options: any) {
  const client = requireClient();

  if (options.list || (!options.add && !options.remove && !options.verify && !options.info)) {
    await listDomains(client);
  } else if (options.add) {
    await addDomain(client, options.add);
  } else if (options.remove) {
    await removeDomain(client, options.remove);
  } else if (options.verify) {
    await verifyDomain(client, options.verify);
  } else if (options.info) {
    await domainInfo(client, options.info);
  }
}

// ─── List ─────────────────────────────────────────────────────────────────
async function listDomains(client: Chariow) {
  const spinner = ora('Fetching custom domains...').start();
  try {
    const domains = await client.dns.list();
    spinner.succeed(`Found ${domains.length} domain(s)\n`);

    if (domains.length === 0) {
      console.log(C.dim('No domains configured. Add one with: chariow dns --add example.com\n'));
      return;
    }

    const table = new Table({
      head: [C.cyan('ID'), C.cyan('Domain'), C.cyan('Type'), C.cyan('Status'), C.cyan('SSL'), C.cyan('Verified')],
      colWidths: [28, 32, 12, 12, 12, 22],
    });

    domains.forEach(d => {
      const statusFn = STATUS_COLOR[d.status] ?? C.text;
      const sslFn    = STATUS_COLOR[d.ssl_status ?? 'pending'] ?? C.text;
      table.push([
        C.dim(d.id.slice(0, 26)),
        C.bold(d.domain),
        C.text(d.type),
        statusFn('● ' + d.status),
        sslFn(d.ssl_status ?? '—'),
        d.verified_at ? C.dim(new Date(d.verified_at).toLocaleDateString()) : C.dim('—'),
      ]);
    });

    console.log(table.toString());
    console.log(C.dim('\n  Tip: chariow dns --verify <id>  to trigger domain verification\n'));
  } catch (err: any) {
    spinner.fail('Failed to load domains');
    console.log(C.error(err.message));
  }
}

// ─── Info ─────────────────────────────────────────────────────────────────
async function domainInfo(client: Chariow, id: string) {
  const spinner = ora(`Loading domain ${id}...`).start();
  try {
    const d = await client.dns.get(id);
    spinner.succeed();

    console.log('\n' + C.bold.cyan('🌐 Domain Details\n'));

    const statusFn = STATUS_COLOR[d.status] ?? C.text;
    const sslFn    = STATUS_COLOR[d.ssl_status ?? 'pending'] ?? C.text;

    const table = new Table({ colWidths: [20, 60] });
    table.push(
      [C.text('ID:'),       C.dim(d.id)],
      [C.text('Domain:'),   C.bold(d.domain)],
      [C.text('Type:'),     d.type],
      [C.text('Status:'),   statusFn('● ' + d.status)],
      [C.text('SSL:'),      sslFn(d.ssl_status ?? '—')],
      [C.text('Created:'),  new Date(d.created_at).toLocaleString()],
      [C.text('Verified:'), d.verified_at ? new Date(d.verified_at).toLocaleString() : 'Not yet'],
    );
    console.log(table.toString());

    if (d.dns_records && d.dns_records.length > 0) {
      console.log('\n' + C.cyan('  DNS Records to configure:\n'));
      const recTable = new Table({
        head: [C.cyan('Type'), C.cyan('Name'), C.cyan('Value'), C.cyan('TTL')],
        colWidths: [8, 24, 38, 8],
      });
      d.dns_records.forEach(r => {
        recTable.push([C.accent(r.type), r.name, C.text(r.value), String(r.ttl ?? 3600)]);
      });
      console.log(recTable.toString());
      console.log(C.dim('\n  Add these records in your DNS provider, then run: chariow dns --verify ' + id + '\n'));
    }
  } catch (err: any) {
    spinner.fail('Domain not found');
    console.log(C.error(err.message));
  }
}

// ─── Add ──────────────────────────────────────────────────────────────────
async function addDomain(client: Chariow, domain?: string) {
  let targetDomain = domain;

  if (!targetDomain) {
    const { input } = await inquirer.prompt([
      {
        type: 'input',
        name: 'input',
        message: '🌐 Domain name (e.g. myshop.com):',
        validate: (v: string) => {
          if (!v.includes('.')) return 'Enter a valid domain';
          return true;
        },
      },
    ]);
    targetDomain = input.trim().toLowerCase().replace(/^https?:\/\//, '');
  }

  const spinner = ora(`Adding ${targetDomain}...`).start();
  try {
    const d = await client.dns.add({ domain: targetDomain! });
    spinner.succeed(C.success(`Domain added: ${d.domain}\n`));

    console.log(`  ID:     ${C.dim(d.id)}`);
    console.log(`  Status: ${(STATUS_COLOR[d.status] ?? C.text)('● ' + d.status)}`);

    if (d.dns_records && d.dns_records.length > 0) {
      console.log('\n' + C.cyan('  Configure these DNS records with your provider:\n'));
      d.dns_records.forEach(r => {
        console.log(`  ${C.accent(r.type.padEnd(6))} ${C.text(r.name.padEnd(20))} → ${r.value}`);
      });
      console.log(C.dim(`\n  After setup: chariow dns --verify ${d.id}\n`));
    }
  } catch (err: any) {
    spinner.fail('Failed to add domain');
    console.log(C.error(err.message));
  }
}

// ─── Verify ───────────────────────────────────────────────────────────────
async function verifyDomain(client: Chariow, id: string) {
  const spinner = ora('Triggering domain verification...').start();
  try {
    const d = await client.dns.verify(id);
    const statusFn = STATUS_COLOR[d.status] ?? C.text;
    if (d.status === 'active') {
      spinner.succeed(C.success(`✓ Domain ${d.domain} is now active!\n`));
    } else {
      spinner.warn(`Verification in progress. Status: ${statusFn(d.status)}`);
      console.log(C.dim('  DNS propagation can take up to 48 hours.\n'));
    }
  } catch (err: any) {
    spinner.fail('Verification failed');
    console.log(C.error(err.message));
  }
}

// ─── Remove ───────────────────────────────────────────────────────────────
async function removeDomain(client: Chariow, id: string) {
  const { ok } = await inquirer.prompt([
    {
      type: 'confirm',
      name: 'ok',
      message: C.error(`⚠ Remove domain ${id}?`),
      default: false,
    },
  ]);
  if (!ok) { console.log(C.warning('\n⚠ Cancelled.\n')); return; }

  const spinner = ora('Removing domain...').start();
  try {
    await client.dns.remove(id);
    spinner.succeed(C.success('Domain removed.\n'));
  } catch (err: any) {
    spinner.fail('Failed to remove domain');
    console.log(C.error(err.message));
  }
}

import chalk from 'chalk';
import ora from 'ora';
import inquirer from 'inquirer';
import Table from 'cli-table3';
import { Chariow } from '../../index.js';
import { getConfig } from '../utils/config.js';
import type { PaymentStatus } from '../../modules/pay.js';

const C = {
  primary: chalk.hex('#6366f1'),
  success: chalk.hex('#10b981'),
  warning: chalk.hex('#f59e0b'),
  error:   chalk.hex('#ef4444'),
  accent:  chalk.hex('#8b5cf6'),
  text:    chalk.hex('#94a3b8'),
  dim:     chalk.dim,
  bold:    chalk.bold,
  cyan:    chalk.cyan,
};

const STATUS_COLOR: Record<string, (s: string) => string> = {
  succeeded:  C.success,
  completed:  C.success,
  pending:    C.warning,
  processing: C.warning,
  failed:     C.error,
  cancelled:  C.error,
  refunded:   C.accent,
};

function requireClient(): Chariow {
  const config = getConfig();
  if (!config?.apiKey) {
    console.log(C.error('\n❌ No API key. Run: chariow config --set <token>\n'));
    process.exit(1);
  }
  return new Chariow(config.apiKey);
}

export async function payCommand(options: any) {
  const client = requireClient();

  if (options.buy) {
    await buyProduct(client, options.buy, options);
  } else if (options.list) {
    await listPayments(client, options);
  } else if (options.get) {
    await getPayment(client, options.get);
  } else if (options.refund) {
    await refundPayment(client, options.refund);
  } else if (options.checkout) {
    await interactiveCheckout(client);
  } else {
    showUsage();
  }
}

// ─── Buy (direct) ─────────────────────────────────────────────────────────
async function buyProduct(client: Chariow, productId: string, options: any) {
  console.log('\n' + C.primary.bold('╔══════════════════════════════════════════════╗'));
  console.log(C.primary.bold('║   💳  CHARIOW PAY  —  Product Checkout       ║'));
  console.log(C.primary.bold('╚══════════════════════════════════════════════╝\n'));

  // Fetch product info first
  const prodSpinner = ora(`Loading product ${productId}...`).start();
  let product: any;
  try {
    product = await client.products.get(productId);
    prodSpinner.succeed(`${product.name}  —  ${C.success(product.pricing?.current_price?.formatted || 'Free')}\n`);
  } catch (err: any) {
    prodSpinner.fail('Product not found');
    console.log(C.error(err.message));
    return;
  }

  const answers = await inquirer.prompt([
    {
      type: 'input',
      name: 'email',
      message: '📧 Customer email:',
      default: options.email,
      validate: (v: string) => v.includes('@') ? true : 'Enter a valid email',
    },
    {
      type: 'input',
      name: 'name',
      message: '👤 Customer name (optional):',
      default: options.name,
    },
    {
      type: 'list',
      name: 'method',
      message: '💳 Payment method:',
      choices: [
        { name: '💳 Card',           value: 'card' },
        { name: '📱 Mobile Money',   value: 'mobile_money' },
        { name: '🏦 Bank Transfer',  value: 'bank_transfer' },
        { name: '🅿️  PayPal',         value: 'paypal' },
        { name: '🔷 Crypto',         value: 'crypto' },
      ],
    },
    {
      type: 'list',
      name: 'currency',
      message: '💱 Currency:',
      choices: ['USD', 'EUR', 'GBP', 'XAF', 'NGN', 'GHS', 'KES'],
      default: product.pricing?.current_price?.currency || 'USD',
    },
    {
      type: 'confirm',
      name: 'confirm',
      message: (a: any) => `\nConfirm purchase of "${product.name}" for ${product.pricing?.current_price?.formatted || 'Free'}?`,
      default: true,
    },
  ]);

  if (!answers.confirm) {
    console.log(C.warning('\n⚠ Payment cancelled.\n'));
    return;
  }

  const spinner = ora('Processing payment via Chariow Pay...').start();
  try {
    const payment = await client.pay.checkout({
      items: [{ product_id: productId, quantity: 1 }],
      customer_email: answers.email,
      customer_name:  answers.name || undefined,
      payment_method: { type: answers.method },
      currency:       answers.currency,
    });

    spinner.succeed(C.success('Checkout created!\n'));
    printPaymentSummary(payment);
  } catch (err: any) {
    spinner.fail('Payment failed');
    console.log(C.error('\n' + err.message + '\n'));
  }
}

// ─── Interactive checkout ─────────────────────────────────────────────────
