import chalk from 'chalk';
import http from 'http';
import { getConfig } from '../utils/config.js';
import { Chariow } from '../../index.js';

const C = {
  primary: chalk.hex('#6366f1'),
  success: chalk.hex('#10b981'),
  warning: chalk.hex('#f59e0b'),
  error:   chalk.hex('#ef4444'),
  accent:  chalk.hex('#8b5cf6'),
  text:    chalk.hex('#94a3b8'),
  dim:     chalk.dim,
  bold:    chalk.bold,
  cyan:    chalk.cyan,
};

function ts(): string {
  return chalk.dim(`[${new Date().toLocaleTimeString()}]`);
}

function log(method: string, path: string, status: number, ms: number) {
  const methodColor = method === 'POST' ? C.accent : C.info ?? C.cyan;
  const statusColor = status < 300 ? C.success : status < 400 ? C.warning : C.error;
  console.log(`  ${ts()} ${methodColor(method.padEnd(6))} ${path.padEnd(40)} ${statusColor(String(status))} ${C.dim(ms + 'ms')}`);
}

function json(res: http.ServerResponse, status: number, data: unknown) {
  const body = JSON.stringify(data, null, 2);
  res.writeHead(status, {
    'Content-Type': 'application/json',
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-API-Key',
  });
  res.end(body);
}

async function readBody(req: http.IncomingMessage): Promise<any> {
  return new Promise((resolve) => {
    let data = '';
    req.on('data', chunk => { data += chunk; });
    req.on('end', () => {
      try { resolve(JSON.parse(data || '{}')); }
      catch { resolve({}); }
    });
  });
}

function getApiKey(req: http.IncomingMessage, fallback?: string): string | null {
  const auth = req.headers['authorization'];
  if (auth?.startsWith('Bearer ')) return auth.slice(7);
  const header = req.headers['x-api-key'];
  if (header) return String(header);
  return fallback || null;
}

// ─── Route handler ────────────────────────────────────────────────────────
async function handleRequest(
  req: http.IncomingMessage,
  res: http.ServerResponse,
  defaultApiKey?: string
): Promise<{ status: number }> {
  const url = new URL(req.url || '/', `http://localhost`);
  const path = url.pathname;
  const method = req.method || 'GET';

  // CORS preflight
  if (method === 'OPTIONS') {
    res.writeHead(204, {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-API-Key',
    });
    res.end();
    return { status: 204 };
  }

  const apiKey = getApiKey(req, defaultApiKey);

  if (!apiKey) {
    json(res, 401, { error: 'Missing API key. Pass via Authorization: Bearer <key> or X-API-Key header.' });
    return { status: 401 };
  }

  const client = new Chariow(apiKey);

  // ── GET /api/function/status ───────────────────────────────────────────
  if (path === '/api/function/status' && method === 'GET') {
    json(res, 200, {
      ok: true,
      service: 'chariow-func',
      version: '2.1.3',
      timestamp: new Date().toISOString(),
      endpoints: [
        'POST /api/function/pay',
        'GET  /api/function/products',
        'GET  /api/function/product/:id',
        'GET  /api/function/store',
        'GET  /api/function/sales',
        'GET  /api/function/payments',
        'POST /api/function/checkout',
        'POST /api/function/webhook/verify',
      ],
    });
    return { status: 200 };
  }

  // ── POST /api/function/pay — buy a product ─────────────────────────────
  if (path === '/api/function/pay' && method === 'POST') {
    const body = await readBody(req);
    const { product_id, quantity, customer_email, customer_name, payment_method, currency, metadata } = body;

    if (!product_id) {
      json(res, 400, { error: 'Missing required field: product_id' });
      return { status: 400 };
    }

    try {
      const payment = await client.pay.checkout({
        items: [{ product_id, quantity: quantity ?? 1 }],
        customer_email,
        customer_name,
        payment_method: payment_method ?? { type: 'card' },
        currency: currency ?? 'USD',
        metadata,
      });
      json(res, 200, { ok: true, payment });
      return { status: 200 };
    } catch (err: any) {
      json(res, 422, { ok: false, error: err.message, details: err.data });
      return { status: 422 };
    }
  }

  // ── POST /api/function/checkout — multi-item checkout ─────────────────
  if (path === '/api/function/checkout' && method === 'POST') {
    const body = await readBody(req);

    if (!body.items || !Array.isArray(body.items)) {
      json(res, 400, { error: 'Missing required field: items (array)' });
      return { status: 400 };
    }

    try {
      const payment = await client.pay.checkout(body);
      json(res, 200, { ok: true, payment });
      return { status: 200 };
    } catch (err: any) {
      json(res, 422, { ok: false, error: err.message, details: err.data });
      return { status: 422 };
    }
  }

  // ── GET /api/function/products ─────────────────────────────────────────
  if (path === '/api/function/products' && method === 'GET') {
    try {
      const perPage = url.searchParams.get('per_page') ? parseInt(url.searchParams.get('per_page')!) : 50;
      const status  = url.searchParams.get('status') || undefined;
      const cursor  = url.searchParams.get('cursor') || undefined;
      const resp = await client.products.list({ per_page: perPage, status, cursor });
      json(res, 200, { ok: true, ...resp });
      return { status: 200 };
    } catch (err: any) {
      json(res, 500, { ok: false, error: err.message });
      return { status: 500 };
    }
  }

  // ── GET /api/function/product/:id ──────────────────────────────────────
  const productMatch = path.match(/^\/api\/function\/product\/([^/]+)$/);
  if (productMatch && method === 'GET') {
    try {
      const product = await client.products.get(productMatch[1]);
      json(res, 200, { ok: true, product });
      return { status: 200 };
    } catch (err: any) {
      json(res, 404, { ok: false, error: err.message });
      return { status: 404 };
    }
  }

  // ── GET /api/function/store ────────────────────────────────────────────
  if (path === '/api/function/store' && method === 'GET') {
    try {
      const store = await client.store.getInfo();
      json(res, 200, { ok: true, store });
      return { status: 200 };
    } catch (err: any) {
      json(res, 500, { ok: false, error: err.message });
      return { status: 500 };
    }
  }

  // ── GET /api/function/sales ────────────────────────────────────────────
  if (path === '/api/function/sales' && method === 'GET') {
    try {
      const perPage = url.searchParams.get('per_page') ? parseInt(url.searchParams.get('per_page')!) : 20;
      const resp = await client.sales.list(undefined, perPage);
      json(res, 200, { ok: true, ...resp });
      return { status: 200 };
    } catch (err: any) {
      json(res, 500, { ok: false, error: err.message });
      return { status: 500 };
    }
  }

  // ── GET /api/function/payments ─────────────────────────────────────────
  if (path === '/api/function/payments' && method === 'GET') {
    try {
      const perPage = url.searchParams.get('per_page') ? parseInt(url.searchParams.get('per_page')!) : 20;
      const resp = await client.pay.list({ per_page: perPage });
      json(res, 200, { ok: true, ...resp });
      return { status: 200 };
    } catch (err: any) {
      json(res, 500, { ok: false, error: err.message });
      return { status: 500 };
    }
  }

  // ── GET /api/function/payment/:id ──────────────────────────────────────
  const paymentMatch = path.match(/^\/api\/function\/payment\/([^/]+)$/);
  if (paymentMatch && method === 'GET') {
    try {
      const payment = await client.pay.get(paymentMatch[1]);
      json(res, 200, { ok: true, payment });
      return { status: 200 };
    } catch (err: any) {
      json(res, 404, { ok: false, error: err.message });
      return { status: 404 };
    }
  }

  // ── POST /api/function/webhook/verify ──────────────────────────────────
  if (path === '/api/function/webhook/verify' && method === 'POST') {
    const body = await readBody(req);
    const signature = req.headers['x-chariow-signature'] as string | undefined;
    json(res, 200, { ok: true, received: true, signature_present: !!signature, payload: body });
    return { status: 200 };
  }

  // ── 404 ────────────────────────────────────────────────────────────────
  json(res, 404, {
    ok: false,
    error: `Route not found: ${method} ${path}`,
    available: [
      'GET  /api/function/status',
      'POST /api/function/pay',
      'POST /api/function/checkout',
      'GET  /api/function/products',
      'GET  /api/function/product/:id',
      'GET  /api/function/store',
      'GET  /api/function/sales',
      'GET  /api/function/payments',
      'GET  /api/function/payment/:id',
      'POST /api/function/webhook/verify',
    ],
  });
  return { status: 404 };
}

// ─── Entry ────────────────────────────────────────────────────────────────
export async function funcCommand(options: any) {
  const config = getConfig();
  const port = options.port ? parseInt(options.port) : 4242;
  const defaultApiKey = config?.apiKey;

  if (!defaultApiKey) {
    console.log(C.warning('\n⚠  No API key in config. Clients must pass their own via header.\n'));
  }

  console.log(C.primary.bold(`
╔══════════════════════════════════════════════════════════════════╗
║   ⚡  CHARIOW FUNC  —  api.function.pay  Local Gateway          ║
╚══════════════════════════════════════════════════════════════════╝
`));

  const server = http.createServer(async (req, res) => {
    const start = Date.now();
    const method = req.method || 'GET';
    const url = req.url || '/';
    let status = 200;
    try {
      const result = await handleRequest(req, res, defaultApiKey);
      status = result.status;
    } catch (err: any) {
      json(res, 500, { ok: false, error: err.message });
      status = 500;
    }
    log(method, url, status, Date.now() - start);
  });

  server.listen(port, '127.0.0.1', () => {
    console.log(C.success(`  ✓ Chariow Func server running on port ${port}\n`));
    console.log(C.bold('  AVAILABLE ENDPOINTS:\n'));

    const endpoints = [
      ['GET',  `/api/function/status`,       'Health check & endpoint list'],
      ['POST', `/api/function/pay`,           'Buy a product  { product_id, customer_email, ... }'],
      ['POST', `/api/function/checkout`,      'Multi-item checkout  { items: [...], ... }'],
      ['GET',  `/api/function/products`,      'List products  ?per_page=50&status=published'],
      ['GET',  `/api/function/product/:id`,   'Get product by ID'],
      ['GET',  `/api/function/store`,         'Store info'],
      ['GET',  `/api/function/sales`,         'Sales list'],
      ['GET',  `/api/function/payments`,      'Payment history'],
      ['GET',  `/api/function/payment/:id`,   'Get payment details'],
      ['POST', `/api/function/webhook/verify`,'Webhook payload receiver'],
    ];

    endpoints.forEach(([m, p, d]) => {
      const mc = m === 'POST' ? C.accent : C.success;
      console.log(`  ${mc(m.padEnd(5))} ${C.primary(`http://localhost:${port}${p.padEnd(38)}`)} ${C.dim(d)}`);
    });

    console.log('\n' + C.bold('  USAGE FROM ANY APP:\n'));
    console.log(C.dim(`  # Buy a product (Node.js / fetch / curl):`));
    console.log(C.text(`  curl -X POST http://localhost:${port}/api/function/pay \\`));
    console.log(C.text(`    -H "Content-Type: application/json" \\`));
    console.log(C.text(`    -H "Authorization: Bearer <your_api_key>" \\`));
    console.log(C.text(`    -d '{"product_id":"<id>","customer_email":"user@example.com"}'\n`));
    console.log(C.dim(`  # JavaScript (React, Vue, etc.):`));
    console.log(C.text(`  fetch('http://localhost:${port}/api/function/pay', {`));
    console.log(C.text(`    method: 'POST',`));
    console.log(C.text(`    headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer <key>' },`));
    console.log(C.text(`    body: JSON.stringify({ product_id: '<id>', customer_email: 'user@example.com' })`));
    console.log(C.text(`  })\n`));
    console.log(C.dim('  Press Ctrl+C to stop the server\n'));
    console.log(C.text('  Incoming requests:\n'));
  });

  process.on('SIGINT', () => {
    console.log(C.warning('\n\n  Shutting down Chariow Func server...\n'));
    server.close(() => process.exit(0));
  });
}

#!/usr/bin/env node

import { Command } from 'commander';
import chalk from 'chalk';
import { interactiveMode }  from './commands/dashboard.js';
import { configCommand }    from './commands/config.js';
import { productsCommand }  from './commands/products.js';
import { exploreCommand }   from './commands/explore.js';
import { salesCommand }     from './commands/sales.js';
import { storeCommand }     from './commands/store.js';
import { wsCommand }        from './commands/ws.js';
import { hooksCommand }     from './commands/hooks.js';
import { dnsCommand }       from './commands/dns.js';
import { payCommand }       from './commands/pay.js';
import { funcCommand }      from './commands/func.js';

const VERSION = '2.2.0';

const banner = chalk.hex('#6366f1')(`
╔════════════════════════════════════════════════════════════════════════════╗
║                                                                            ║
║     ██████╗██╗  ██╗ █████╗ ██████╗ ██╗ ██████╗ ██╗    ██╗               ║
║    ██╔════╝██║  ██║██╔══██╗██╔══██╗██║██╔═══██╗██║    ██║               ║
║    ██║     ███████║███████║██████╔╝██║██║   ██║██║ █╗ ██║               ║
║    ██║     ██╔══██║██╔══██║██╔══██╗██║██║   ██║██║███╗██║               ║
║    ╚██████╗██║  ██║██║  ██║██║  ██║██║╚██████╔╝╚███╔███╔╝               ║
║     ╚═════╝╚═╝  ╚═╝╚═╝  ╚═╝╚═╝  ╚═╝╚═╝ ╚═════╝  ╚══╝╚══╝                ║
║                                                                            ║
║     Enterprise Commerce CLI  `) + chalk.hex('#94a3b8')(`v${VERSION}`) + chalk.hex('#6366f1')(`                                        ║
║     Manage · Pay · Hooks · DNS · WebSocket · Func                        ║
║                                                                            ║
╚════════════════════════════════════════════════════════════════════════════╝
`);

console.log(banner);

const program = new Command();

program
  .name('chariow')
  .description(chalk.hex('#94a3b8')('⚡ CLI for Chariow — Next generation e-commerce platform'))
  .version(VERSION)
  .helpOption('-h, --help', chalk.hex('#94a3b8')('Display help information'));

// ─── dashboard ───────────────────────────────────────────────────────────────
program
  .command('dashboard')
  .alias('d')
  .description(chalk.hex('#10b981')('📊 Interactive TUI dashboard  (Products · Sales · Store)'))
  .action(interactiveMode);

// ─── config ──────────────────────────────────────────────────────────────────
program
  .command('config')
  .description(chalk.hex('#f59e0b')('🔧 Manage CLI configuration'))
  .option('-s, --set <token>', 'Set API token')
  .option('-g, --get', 'Get current token')
  .option('-r, --remove', 'Remove token')
  .option('--reset', 'Reset all configuration')
  .action(configCommand);

// ─── products ────────────────────────────────────────────────────────────────
program
  .command('products')
  .description(chalk.hex('#3b82f6')('📦 Product management'))
  .option('-l, --list', 'List all products')
  .option('-g, --get <id>', 'Get product by ID')
  .option('-s, --search <term>', 'Search products')
  .option('-c, --create', 'Create a new product (interactive)')
  .option('--publish <id>', 'Publish a product')
  .option('--unpublish <id>', 'Unpublish a product (back to draft)')
  .option('-d, --delete <id>', 'Delete a product')
  .option('--stats', 'Show product statistics')
  .option('--status <status>', 'Filter by status when listing  (published|draft)')
  .option('--limit <n>', 'Number of products to fetch  (default: 50)')
  .action(productsCommand);

// ─── sales ───────────────────────────────────────────────────────────────────
program
  .command('sales')
  .description(chalk.hex('#10b981')('🛒 Sales & orders management'))
  .option('-l, --list', 'List recent sales')
  .option('-g, --get <id>', 'Get sale by ID')
  .option('--stats', 'Show sales statistics')
  .option('--limit <n>', 'Number of sales to fetch  (default: 20)')
  .action(salesCommand);

// ─── store ───────────────────────────────────────────────────────────────────
program
  .command('store')
  .description(chalk.hex('#8b5cf6')('🏪 Store information & appearance'))
  .action(storeCommand);

// ─── explore ─────────────────────────────────────────────────────────────────
program
  .command('explore')
  .description(chalk.hex('#8b5cf6')('🔍 Explore the Chariow marketplace  (stores & products)'))
  .option('-s, --search <term>', 'Search stores by name')
  .option('--store <slug>', 'View a specific store and its products')
  .option('-t, --top', 'Top stores by product count')
  .option('-p, --products [category]', 'Browse all published products  (optional category filter)')
  .action(exploreCommand);

// ─── pay ─────────────────────────────────────────────────────────────────────
program
  .command('pay')
  .description(chalk.hex('#10b981')('💳 Chariow Pay  —  payments & checkout'))
  .option('--checkout', 'Interactive checkout wizard')
  .option('--buy <product_id>', 'Buy a specific product')
  .option('-l, --list', 'List payment history')
  .option('-g, --get <id>', 'Get payment details')
  .option('--refund <id>', 'Refund a payment')
  .option('--status <status>', 'Filter payments by status  (pending|succeeded|failed|refunded)')
  .option('--limit <n>', 'Number of payments  (default: 20)')
  .option('--email <email>', 'Customer email  (used with --buy)')
  .option('--name <name>', 'Customer name  (used with --buy)')
  .action(payCommand);

// ─── hooks ───────────────────────────────────────────────────────────────────
program
  .command('hooks')
  .description(chalk.hex('#f59e0b')('🔗 Webhook management'))
  .option('-l, --list', 'List all webhooks')
  .option('--get <id>', 'Get webhook details')
  .option('--create', 'Create a new webhook  (interactive)')
  .option('--delete <id>', 'Delete a webhook')
  .option('--test <id>', 'Send a test payload to a webhook')
  .option('--deliveries <id>', 'View delivery history for a webhook')
  .action(hooksCommand);

// ─── dns ─────────────────────────────────────────────────────────────────────
program
  .command('dns')
  .description(chalk.hex('#3b82f6')('🌐 Custom domain & DNS management'))
  .option('-l, --list', 'List all custom domains')
  .option('--info <id>', 'Get domain details and DNS records')
  .option('--add [domain]', 'Add a custom domain  (interactive if omitted)')
  .option('--verify <id>', 'Trigger domain verification')
  .option('--remove <id>', 'Remove a custom domain')
  .action(dnsCommand);

// ─── ws ──────────────────────────────────────────────────────────────────────
program
  .command('ws')
  .description(chalk.hex('#6366f1')('🔌 WebSocket live event monitor'))
  .option('--events <types>', 'Comma-separated event types  (default: all)  e.g. sale,product')
  .option('--store', 'Subscribe to store events')
  .option('--product <id>', 'Subscribe to a specific product')
  .action(wsCommand);

// ─── func ────────────────────────────────────────────────────────────────────
program
  .command('func')
  .description(chalk.hex('#8b5cf6')('⚡ api.function.pay — Local HTTP gateway for cross-app payments'))
  .option('--port <n>', 'Port to listen on  (default: 4242)')
  .action(funcCommand);

// ─── list ─────────────────────────────────────────────────────────────────────
program
  .command('list')
  .description('List all available commands')
  .action(showCommands);

// ─── help ─────────────────────────────────────────────────────────────────────
program
  .command('help')
  .description(chalk.hex('#94a3b8')('Show help information'))
  .action(() => program.outputHelp());

// ─── Show commands ────────────────────────────────────────────────────────────
function showCommands() {
  console.log(chalk.hex('#6366f1').bold('\n📋 ALL COMMANDS\n'));

  const sections: Array<{ title: string; color: string; cmds: [string, string][] }> = [
    {
      title: 'CORE',
      color: '#94a3b8',
      cmds: [
        ['dashboard, d',  'Interactive TUI  (Products · Sales · Store)'],
        ['config',        'Manage API key  (set, get, remove)'],
      ],
    },
    {
      title: 'PRODUCTS',
      color: '#3b82f6',
      cmds: [
        ['products --list',             'List all products'],
        ['products --create',           'Create product  (interactive form)'],
        ['products --publish <id>',     'Publish a product'],
        ['products --unpublish <id>',   'Move product to draft'],
        ['products --delete <id>',      'Delete a product'],
        ['products --search <term>',    'Search products'],
        ['products --stats',            'Product statistics'],
      ],
    },
    {
      title: 'PAY  —  Chariow Pay',
      color: '#10b981',
      cmds: [
        ['pay --checkout',         'Interactive checkout wizard'],
        ['pay --buy <product_id>', 'Buy a product directly'],
        ['pay --list',             'Payment history'],
        ['pay --get <id>',         'Payment details'],
        ['pay --refund <id>',      'Refund a payment'],
      ],
    },
    {
      title: 'FUNC  —  api.function.pay',
      color: '#8b5cf6',
      cmds: [
        ['func',              'Start local HTTP gateway on port 4242'],
        ['func --port <n>',   'Start on custom port'],
      ],
    },
    {
      title: 'WEBSOCKET',
      color: '#6366f1',
      cmds: [
        ['ws',                       'Live event monitor  (all events)'],
        ['ws --events sale,product', 'Filter specific event types'],
        ['ws --store',               'Subscribe to store events'],
        ['ws --product <id>',        'Subscribe to a product'],
      ],
    },
    {
      title: 'HOOKS',
      color: '#f59e0b',
      cmds: [
        ['hooks --list',           'List all webhooks'],
        ['hooks --create',         'Create webhook  (interactive)'],
        ['hooks --test <id>',      'Send test payload'],
        ['hooks --deliveries <id>','Delivery history'],
        ['hooks --delete <id>',    'Delete webhook'],
      ],
    },
    {
      title: 'DNS',
      color: '#3b82f6',
      cmds: [
        ['dns --list',        'List custom domains'],
        ['dns --add <domain>','Add a domain'],
        ['dns --verify <id>', 'Verify domain'],
        ['dns --info <id>',   'DNS records & status'],
        ['dns --remove <id>', 'Remove domain'],
      ],
    },
    {
      title: 'OTHER',
      color: '#94a3b8',
      cmds: [
        ['sales --list',   'Sales & orders'],
        ['sales --stats',  'Sales statistics'],
        ['store',          'Store info & appearance'],
        ['explore',        'Marketplace browser  (all stores & products)'],
      ],
    },
  ];

  sections.forEach(({ title, color, cmds }) => {
    console.log(chalk.hex(color).bold(`  ${title}\n`));
    cmds.forEach(([cmd, desc]) => {
      console.log(`    ${chalk.hex(color)(`chariow ${cmd.padEnd(36)}`)} ${chalk.hex('#94a3b8')(desc)}`);
    });
    console.log('');
  });

  console.log(chalk.hex('#94a3b8')('  💡 chariow <command> --help  for per-command options\n'));
}

// ─── Error output ─────────────────────────────────────────────────────────────
program.configureOutput({
  outputError: (str, write) => write(chalk.hex('#ef4444')(str)),
});

// ─── Entry ────────────────────────────────────────────────────────────────────
if (process.argv.length === 2) {
  console.log(chalk.hex('#94a3b8')('🚀 Starting interactive dashboard...\n'));
  interactiveMode();
} else {
  program.parse();
}

// ─── Global handlers ──────────────────────────────────────────────────────────
process.on('unhandledRejection', (error: any) => {
  console.error(chalk.hex('#ef4444')(`\n❌ ${error?.message || error}\n`));
  process.exit(1);
});
process.on('SIGINT', () => {
  console.log(chalk.hex('#94a3b8')('\n\n👋 Goodbye!\n'));
  process.exit(0);
});
process.on('SIGTERM', () => {
  console.log(chalk.hex('#94a3b8')('\n\n👋 Terminated.\n'));
  process.exit(0);
});

