const inputs = [
  'https://chariow.com/store/myshop/products/my-product-slug',
  'https://myshop.chariow.com/products/cool-t-shirt',
  'https://chariow.com/products/prod_abc123',
  'my-product-slug',
  'prod_abc123xyz',
];

function parseProductInput(input) {
  input = input.trim();
  if (input.startsWith('http://') || input.startsWith('https://')) {
    try {
      const u = new URL(input);
      const m1 = u.pathname.match(/\/store\/([^\/]+)\/products\/([^\/]+)/);
      if (m1) return { type: 'url', value: m1[2], storeSlug: m1[1] };
      const m2 = u.pathname.match(/\/products\/([^\/]+)/);
      if (m2) return { type: 'url', value: m2[1] };
      const sub = u.hostname.match(/^([^.]+)\.chariow\.com\$/);
      const mp  = u.pathname.match(/\/products\/([^\/]+)/);
      if (sub && mp) return { type: 'url', value: mp[1], storeSlug: sub[1] };
    } catch {}
  }
  if (/^(prod_|pay_|[0-9a-f-]{36}\$)/.test(input)) return { type: 'id', value: input };
  return { type: 'slug', value: input };
}

inputs.forEach(i => console.log(JSON.stringify(parseProductInput(i))));
