export interface ParsedProductInput {
  type: 'url' | 'slug' | 'id'
  value: string
  storeSlug?: string
}

/**
 * Parse a product URL, slug, or ID into a structured object.
 *
 * Accepted formats:
 *   https://chariow.com/store/:store/products/:slug
 *   https://:store.chariow.com/products/:slug
 *   https://chariow.com/products/:slug
 *   prod_abc123  /  pay_xyz  /  UUID
 *   plain-slug
 */
export function parseProductInput(input: string): ParsedProductInput {
  input = input.trim()

  if (input.startsWith('http://') || input.startsWith('https://')) {
    try {
      const u = new URL(input)

      // https://chariow.com/store/:storeSlug/products/:productSlug
      const storeProductMatch = u.pathname.match(/\/store\/([^/]+)\/products\/([^/]+)/)
      if (storeProductMatch) {
        return { type: 'url', value: storeProductMatch[2], storeSlug: storeProductMatch[1] }
      }

      // https://:storeSlug.chariow.com/products/:productSlug
      const subdomainMatch  = u.hostname.match(/^([^.]+)\.chariow\.com$/)
      const productPathMatch = u.pathname.match(/\/products\/([^/]+)/)
      if (subdomainMatch && productPathMatch) {
        return { type: 'url', value: productPathMatch[1], storeSlug: subdomainMatch[1] }
      }

      // https://chariow.com/products/:productSlug
      if (productPathMatch) {
        return { type: 'url', value: productPathMatch[1] }
      }

      // Fallback — last non-empty path segment
      const segments = u.pathname.split('/').filter(Boolean)
      if (segments.length > 0) {
        return { type: 'url', value: segments[segments.length - 1] }
      }
    } catch {
      /* invalid URL — fall through to slug/id detection */
    }
  }

  // prod_ / pay_ prefixed IDs, or UUID v4
  if (/^(prod_|pay_)/.test(input) ||
      /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/.test(input)) {
    return { type: 'id', value: input }
  }

  return { type: 'slug', value: input }
}

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { ChariowError } from '../../src/errors.js'

describe('ChariowError', () => {
  it('is an instance of Error', () => {
    const err = new ChariowError('boom')
    assert.ok(err instanceof Error)
  })

  it('is an instance of ChariowError', () => {
    const err = new ChariowError('boom')
    assert.ok(err instanceof ChariowError)
  })

  it('sets name to "ChariowError"', () => {
    const err = new ChariowError('something failed')
    assert.equal(err.name, 'ChariowError')
  })

  it('sets message correctly', () => {
    const err = new ChariowError('payment declined')
    assert.equal(err.message, 'payment declined')
  })

  it('sets status when provided', () => {
    const err = new ChariowError('not found', 404)
    assert.equal(err.status, 404)
  })

  it('sets data when provided', () => {
    const data = { field: 'email', code: 'invalid_format' }
    const err = new ChariowError('validation error', 422, data)
    assert.deepEqual(err.data, data)
  })

  it('status is undefined when not provided', () => {
    const err = new ChariowError('unknown')
    assert.equal(err.status, undefined)
  })

  it('data is undefined when not provided', () => {
    const err = new ChariowError('unknown', 500)
    assert.equal(err.data, undefined)
  })

  it('status 0 is preserved', () => {
    const err = new ChariowError('network error', 0)
    assert.equal(err.status, 0)
  })

  it('data can be any value (string)', () => {
    const err = new ChariowError('err', 400, 'raw error string')
    assert.equal(err.data, 'raw error string')
  })

  it('data can be an array', () => {
    const err = new ChariowError('err', 400, ['e1', 'e2'])
    assert.deepEqual(err.data, ['e1', 'e2'])
  })

  it('can be caught as Error', () => {
    try {
      throw new ChariowError('intentional', 500)
    } catch (e) {
      assert.ok(e instanceof Error)
      assert.ok(e instanceof ChariowError)
      assert.equal((e as ChariowError).status, 500)
    }
  })
})

import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { parseProductInput } from '../../src/cli/utils/url-parser.js'

describe('parseProductInput — Full store product URL', () => {
  it('extracts slug and storeSlug from /store/:store/products/:slug', () => {
    const r = parseProductInput('https://chariow.com/store/myshop/products/my-product')
    assert.equal(r.type, 'url')
    assert.equal(r.value, 'my-product')
    assert.equal(r.storeSlug, 'myshop')
  })

  it('handles slugs with hyphens and numbers', () => {
    const r = parseProductInput('https://chariow.com/store/shop-42/products/item-007')
    assert.equal(r.value, 'item-007')
    assert.equal(r.storeSlug, 'shop-42')
  })

  it('works with HTTP (non-HTTPS)', () => {
    const r = parseProductInput('http://chariow.com/store/mystore/products/t-shirt')
    assert.equal(r.type, 'url')
    assert.equal(r.value, 't-shirt')
  })
})

describe('parseProductInput — Subdomain URL', () => {
  it('extracts slug from :store.chariow.com/products/:slug', () => {
    const r = parseProductInput('https://myshop.chariow.com/products/cool-hat')
    assert.equal(r.type, 'url')
    assert.equal(r.value, 'cool-hat')
    assert.equal(r.storeSlug, 'myshop')
  })

  it('handles multi-segment subdomain product paths', () => {
    const r = parseProductInput('https://boutique.chariow.com/products/sneakers-2024')
    assert.equal(r.value, 'sneakers-2024')
    assert.equal(r.storeSlug, 'boutique')
  })
})

describe('parseProductInput — Direct product URL', () => {
  it('extracts slug from /products/:slug without store', () => {
