/**
 * Integration tests for ChariowPay HTTP server.
 * Starts a real server on port 34242, makes live fetch() requests.
 */
import { describe, it, before, after } from 'node:test'
import assert from 'node:assert/strict'
import { ChariowPay } from '../../src/modules/chariow-pay-server.js'

const PORT = 34242
const BASE = `http://localhost:${PORT}`

let pay: ChariowPay

before(() => {
  pay = new ChariowPay({
    Crud:   'testkey-chariow-sdk',
    Type:   'APP',
    Devis:  'USD, XAF',
    Port:   PORT,
  })

  // ── Route registrations ────────────────────────────────────────────────
  pay.get('/', 'html', (_req, res) => {
    return res.html('<html><body><h1>ChariowPay Test Server</h1></body></html>')
  })

  pay.get('/health', (req, res) => {
    return res.json({ ok: true, service: 'chariow-pay-test' })
  })

  pay.post('/echo', (req, res) => {
    return res.json({ echoed: req.body })
  })

  pay.post('/pay', 'json', (req, res) => {
    if (!req.body.product_id) {
      return res.json({ error: 'product_id required' }, 400)
    }
    return res.json({
      id:       'pay_test_123',
      status:   'pending',
      amount:   req.body.amount ?? 1000,
      currency: 'USD',
      product_id: req.body.product_id,
    })
  })

  pay.get('/user/:id', (req, res) => {
    return res.json({ userId: req.path.split('/').pop() })
  })

  pay.get('/redirect-test', (req, res) => {
    return res.redirect('/health', 302)
  })

  pay.put('/update', (req, res) => {
    return res.json({ updated: true, data: req.body })
  })

  pay.delete('/delete', (req, res) => {
    return res.json({ deleted: true })
  })

  // Start server (non-blocking)
  pay.listen(PORT)
})

after(() => {
  pay.close()
})

// ─── Basic reachability ───────────────────────────────────────────────────────

describe('ChariowPay server — basic reachability', () => {
  it('server is running after listen()', () => {
    assert.equal(pay.isRunning, true)
  })

  it('GET / → 200 with HTML body', async () => {
    const res = await fetch(`${BASE}/`)
    assert.equal(res.status, 200)
    const text = await res.text()
    assert.ok(text.includes('ChariowPay Test Server'))
  })

  it('GET /health → 200 with JSON', async () => {
    const res  = await fetch(`${BASE}/health`)
    const body = await res.json() as any
    assert.equal(res.status, 200)
    assert.equal(body.ok, true)
    assert.equal(body.service, 'chariow-pay-test')
  })
})

// ─── POST routes ──────────────────────────────────────────────────────────────

describe('ChariowPay server — POST routes', () => {
  it('POST /echo → echoes JSON body', async () => {
    const payload = { msg: 'hello', value: 42 }
    const res = await fetch(`${BASE}/echo`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify(payload),
    })
    const body = await res.json() as any
    assert.equal(res.status, 200)
    assert.deepEqual(body.echoed, payload)
  })

  it('POST /pay with product_id → 200 with payment object', async () => {
    const res = await fetch(`${BASE}/pay`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ product_id: 'prod_123', amount: 2500 }),
    })
    const body = await res.json() as any
    assert.equal(res.status, 200)
    assert.equal(body.product_id, 'prod_123')
    assert.equal(body.currency, 'USD')
  })

  it('POST /pay without product_id → 400 error', async () => {
    const res = await fetch(`${BASE}/pay`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({}),
    })
    const body = await res.json() as any
    assert.equal(res.status, 400)
    assert.ok(body.error)
  })
})

// ─── PUT / DELETE ─────────────────────────────────────────────────────────────

describe('ChariowPay server — PUT and DELETE routes', () => {
  it('PUT /update → 200 with updated flag', async () => {
    const res = await fetch(`${BASE}/update`, {
      method:  'PUT',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ name: 'New Name' }),
    })
    const body = await res.json() as any
    assert.equal(res.status, 200)
    assert.equal(body.updated, true)
    assert.deepEqual(body.data, { name: 'New Name' })
  })

  it('DELETE /delete → 200 with deleted flag', async () => {
    const res = await fetch(`${BASE}/delete`, { method: 'DELETE' })
    const body = await res.json() as any
    assert.equal(res.status, 200)
    assert.equal(body.deleted, true)
  })
})

// ─── 404 & Unknown routes ─────────────────────────────────────────────────────

describe('ChariowPay server — 404 handling', () => {
  it('GET /unknown → 404', async () => {
    const res = await fetch(`${BASE}/unknown-route-xyz`)
    assert.equal(res.status, 404)
  })

  it('404 body contains error key', async () => {
    const res  = await fetch(`${BASE}/does-not-exist`)
    const body = await res.json() as any
    assert.ok(body.error || body.routes)
  })

  it('POST to GET-only route → 404', async () => {
    const res = await fetch(`${BASE}/health`, { method: 'POST' })
    assert.equal(res.status, 404)
  })
})

// ─── CORS headers ─────────────────────────────────────────────────────────────

describe('ChariowPay server — CORS', () => {
  it('OPTIONS → 204 preflight', async () => {
    const res = await fetch(`${BASE}/pay`, {
      method: 'OPTIONS',
      headers: { 'Origin': 'http://localhost:3000' },
    })
    assert.equal(res.status, 204)
  })

  it('GET / has Access-Control-Allow-Origin: *', async () => {
    const res = await fetch(`${BASE}/`)
    assert.equal(res.headers.get('access-control-allow-origin'), '*')
  })

  it('POST /echo has Access-Control-Allow-Origin: *', async () => {
    const res = await fetch(`${BASE}/echo`, {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    '{}',
    })
    assert.equal(res.headers.get('access-control-allow-origin'), '*')
  })
})

// ─── X-Powered-By header ─────────────────────────────────────────────────────

describe('ChariowPay server — custom headers', () => {
  it('responses include X-Powered-By: ChariowPay', async () => {
    const res = await fetch(`${BASE}/health`)
    assert.equal(res.headers.get('x-powered-by'), 'ChariowPay')
  })

  it('responses include X-Response-Time header', async () => {
    const res = await fetch(`${BASE}/health`)
    const rt  = res.headers.get('x-response-time')
    assert.ok(rt && rt.endsWith('ms'), `Expected X-Response-Time in ms format, got: ${rt}`)
  })
})

// ─── Redirect ────────────────────────────────────────────────────────────────

describe('ChariowPay server — redirect', () => {
  it('GET /redirect-test returns Location header', async () => {
    const res = await fetch(`${BASE}/redirect-test`, { redirect: 'manual' })
    assert.ok(res.status === 302 || res.status === 200) // fetch may follow redirect
    const loc = res.headers.get('location')
    if (res.status === 302) {
      assert.equal(loc, '/health')
    }
  })
})

/**
 * Integration tests for the Chariow Serve HTTP gateway.
 * Creates a lightweight gateway using the serve.ts handleRequest logic,
 * starts on port 34243, and makes live fetch() requests.
 *
 * Only tests endpoints that do NOT require real Chariow API calls
 * (health, auth, CORS, static responses) so no real API key is needed.
 */
import { describe, it, before, after, beforeEach, afterEach } from 'node:test'
import assert from 'node:assert/strict'
import http from 'node:http'
import { handleGatewayRequest } from '../../src/cli/commands/serve.js'

const PORT    = 34243
const BASE    = `http://localhost:${PORT}`
const API_KEY = 'test-chariow-key-12345'

let server: http.Server

before(async () => {
  server = http.createServer(async (req, res) => {
    try {
      await handleGatewayRequest(req, res, API_KEY)
    } catch (err: any) {
      res.writeHead(500, { 'Content-Type': 'application/json' })
      res.end(JSON.stringify({ error: err.message }))
    }
  })
  await new Promise<void>((resolve) => server.listen(PORT, '127.0.0.1', resolve))
})

after(async () => {
  await new Promise<void>((resolve) => server.close(() => resolve()))
})

// ─── CORS preflight ───────────────────────────────────────────────────────────

describe('Gateway — CORS preflight', () => {
  it('OPTIONS → 204 (no API key required)', async () => {
    const res = await fetch(`${BASE}/v1/products`, { method: 'OPTIONS' })
    assert.equal(res.status, 204)
  })

  it('OPTIONS has Access-Control-Allow-Origin: *', async () => {
    const res = await fetch(`${BASE}/v1/balance`, { method: 'OPTIONS' })
    assert.equal(res.headers.get('access-control-allow-origin'), '*')
  })

  it('OPTIONS has Access-Control-Allow-Methods header', async () => {
    const res = await fetch(`${BASE}/v1/charges`, { method: 'OPTIONS' })
    const methods = res.headers.get('access-control-allow-methods') ?? ''
    assert.ok(methods.includes('POST'))
    assert.ok(methods.includes('GET'))
    assert.ok(methods.includes('DELETE'))
  })
})

// ─── Authentication ───────────────────────────────────────────────────────────

describe('Gateway — authentication', () => {
  it('no API key → 401', async () => {
    const res = await fetch(`${BASE}/health`)
    assert.equal(res.status, 401)
  })

  it('401 body has error.code = missing_api_key', async () => {
    const res  = await fetch(`${BASE}/health`)
    const body = await res.json() as any
    assert.equal(body.error?.code, 'missing_api_key')
  })

  it('Authorization: Bearer <key> is accepted', async () => {
    const res = await fetch(`${BASE}/health`, {
      headers: { Authorization: `Bearer ${API_KEY}` },
    })
    assert.equal(res.status, 200)
  })

  it('X-API-Key header is accepted', async () => {
    const res = await fetch(`${BASE}/health`, {
      headers: { 'X-API-Key': API_KEY },
    })
    assert.equal(res.status, 200)
  })
})

// ─── Health endpoints ─────────────────────────────────────────────────────────

describe('Gateway — health endpoints', () => {
  const H = { Authorization: `Bearer ${API_KEY}` }

  it('GET / → 200', async () => {
    const res = await fetch(`${BASE}/`, { headers: H })
    assert.equal(res.status, 200)
  })

  it('GET /health → 200', async () => {
    const res = await fetch(`${BASE}/health`, { headers: H })
    assert.equal(res.status, 200)
  })

  it('GET /health body has ok: true', async () => {
    const body = await fetch(`${BASE}/health`, { headers: H }).then(r => r.json()) as any
    assert.equal(body.ok, true)
  })

  it('GET /health body has service field', async () => {
    const body = await fetch(`${BASE}/health`, { headers: H }).then(r => r.json()) as any
    assert.ok(body.service)
  })

  it('GET /v1/status → 200', async () => {
    const res = await fetch(`${BASE}/v1/status`, { headers: H })
    assert.equal(res.status, 200)
  })

  it('GET /v1/status body has endpoints array', async () => {
    const body = await fetch(`${BASE}/v1/status`, { headers: H }).then(r => r.json()) as any
    assert.ok(Array.isArray(body.endpoints))
    assert.ok(body.endpoints.length > 0)
  })
})

// ─── Response format ──────────────────────────────────────────────────────────

describe('Gateway — response format', () => {
  const H = { Authorization: `Bearer ${API_KEY}`, 'Content-Type': 'application/json' }

  it('all responses have Content-Type: application/json', async () => {
    const res = await fetch(`${BASE}/health`, { headers: H })
    assert.ok(res.headers.get('content-type')?.includes('application/json'))
  })

  it('all responses have Access-Control-Allow-Origin: *', async () => {
    const res = await fetch(`${BASE}/health`, { headers: H })
    assert.equal(res.headers.get('access-control-allow-origin'), '*')
  })

  it('all responses have X-Powered-By header', async () => {
    const res = await fetch(`${BASE}/health`, { headers: H })
    assert.ok(res.headers.get('x-powered-by'))
  })
})

// ─── 404 handling ─────────────────────────────────────────────────────────────

describe('Gateway — 404 handling', () => {
  const H = { Authorization: `Bearer ${API_KEY}` }

  it('unknown GET route → 404', async () => {
    const res = await fetch(`${BASE}/v1/nonexistent`, { headers: H })
    assert.equal(res.status, 404)
  })

  it('404 body has error.code = route_not_found', async () => {
    const body = await fetch(`${BASE}/v1/nonexistent`, { headers: H }).then(r => r.json()) as any
    assert.equal(body.error?.code, 'route_not_found')
  })
})

// ─── Customers endpoint (no API call) ─────────────────────────────────────────

describe('Gateway — POST /v1/customers (no API call)', () => {
  const H = { Authorization: `Bearer ${API_KEY}`, 'Content-Type': 'application/json' }

  it('POST with email → 201', async () => {
    const res = await fetch(`${BASE}/v1/customers`, {
      method: 'POST', headers: H,
      body: JSON.stringify({ email: 'test@example.com', name: 'Test User' }),
    })
    assert.equal(res.status, 201)
  })

  it('POST customer response has id, object, email', async () => {
    const body = await fetch(`${BASE}/v1/customers`, {
      method: 'POST', headers: H,
      body: JSON.stringify({ email: 'user@chariow.com' }),
    }).then(r => r.json()) as any
    assert.equal(body.object, 'customer')
    assert.ok(body.id?.startsWith('cus_'))
    assert.equal(body.email, 'user@chariow.com')
  })

  it('POST without email → 400', async () => {
    const res = await fetch(`${BASE}/v1/customers`, {
      method: 'POST', headers: H,
      body: JSON.stringify({ name: 'No Email' }),
    })
    assert.equal(res.status, 400)
  })
})

// ─── Payment intents — no-API-call paths ──────────────────────────────────────

describe('Gateway — POST /v1/payment_intents (no items → no API call)', () => {
  const H = { Authorization: `Bearer ${API_KEY}`, 'Content-Type': 'application/json' }

  it('missing amount+currency → 400', async () => {
    const res = await fetch(`${BASE}/v1/payment_intents`, {
      method: 'POST', headers: H,
      body: JSON.stringify({ customer_email: 'u@ex.com' }),
    })
    assert.equal(res.status, 400)
  })

  it('amount+currency without items → 201 with checkout_url: null', async () => {
    const body = await fetch(`${BASE}/v1/payment_intents`, {
      method: 'POST', headers: H,
      body: JSON.stringify({ amount: 5000, currency: 'usd', customer_email: 'u@ex.com' }),
    }).then(r => r.json()) as any
    assert.equal(body.object, 'payment_intent')
    assert.equal(body.amount, 5000)
    assert.equal(body.currency, 'usd')
    assert.equal(body.checkout_url, null)
    assert.ok(body.client_secret)
  })

  it('cancel intent → 200 with status: canceled', async () => {
    const res = await fetch(`${BASE}/v1/payment_intents/pi_test123/cancel`, {
      method: 'POST', headers: H, body: '{}',
    })
    const body = await res.json() as any
    assert.equal(res.status, 200)
    assert.equal(body.status, 'canceled')
    assert.equal(body.object, 'payment_intent')
  })
})

// ─── Charges — no-API-call path ───────────────────────────────────────────────

describe('Gateway — POST /v1/charges (no product → no API call)', () => {
  const H = { Authorization: `Bearer ${API_KEY}`, 'Content-Type': 'application/json' }

  it('missing amount → 400', async () => {
    const res = await fetch(`${BASE}/v1/charges`, {
      method: 'POST', headers: H,
      body: JSON.stringify({ currency: 'usd' }),
    })
    assert.equal(res.status, 400)
  })

  it('amount+currency without product_id → 201 with status: succeeded', async () => {
    const body = await fetch(`${BASE}/v1/charges`, {
      method: 'POST', headers: H,
      body: JSON.stringify({ amount: 2000, currency: 'eur', customer_email: 'u@ex.com' }),
    }).then(r => r.json()) as any
    // Returns 201 with a charge object
    assert.equal(body.object, 'charge')
    assert.equal(body.amount, 2000)
  })
})

